interface WorldFormProps {
    isOpen: boolean;
    onClose: () => void;
    onSave: (item: any) => void;
    itemToEdit: SettingItem | null;
    allSettings: SettingItem[];
    onOpenWorldGenModal: (data: Partial<SettingItem> | null) => void;
    onShowHelp: () => void;
    isMobile?: boolean;
}

const fieldKeyToTemplateMap = new Map<string, { key: string, name: string }>();
Object.entries(worldTemplates).forEach(([templateKey, template]) => {
    template.fields.forEach(field => {
        fieldKeyToTemplateMap.set(field.key, { key: templateKey, name: template.name });
    });
});

const initialEmptyWorldState: Partial<SettingItem> = {
    name: '',
    fields: [],
    longDescription: '',
    memo: '',
    exportDescription: '',
    mapImageUrl: '',
};

export const WorldForm: React.FC<WorldFormProps> = ({
    isOpen,
    onClose,
    onSave,
    itemToEdit,
    onOpenWorldGenModal,
    onShowHelp,
    isMobile = false,
}) => {
    const [name, setName] = useState('');
    const [fields, setFields] = useState<Field[]>([]);
    const [longDescription, setLongDescription] = useState('');
    const [memo, setMemo] = useState('');
    const [exportDescription, setExportDescription] = useState('');
    const [mapImageUrl, setMapImageUrl] = useState('');

    const [activeTab, setActiveTab] = useState('profile');
    const [isMapViewerOpen, setIsMapViewerOpen] = useState(false);

    const [isConfirmCloseOpen, setIsConfirmCloseOpen] = useState(false);
    const [initialStateString, setInitialStateString] = useState('');
    const closeButtonRef = useRef(null);
    const [expandedGroups, setExpandedGroups] = useState<Record<string, boolean>>({});

    const [isAiAssistantHelpOpen, setIsAiAssistantHelpOpen] = useState(false);
    const aiAssistantHelpRef = useRef(null);

    // 編集済みフラグ管理
    const [editedFields, setEditedFields] = useState<Set<string>>(new Set());

    const worldFormData = useStore(state => state.worldFormData);
    const resetFormData = useStore(state => state.resetFormData);

    const populateState = (data) => {
        const safeData = data || initialEmptyWorldState;
        setName(safeData.name || '');
        setLongDescription(safeData.longDescription || '');
        setMemo(safeData.memo || '');
        setExportDescription(safeData.exportDescription || '');
        setMapImageUrl(safeData.mapImageUrl || '');

        if (safeData.fields) {
            const initialFields = (safeData.fields || []).map(f => {
                const templateInfo = fieldKeyToTemplateMap.get(f.key);
                return { 
                    ...f, 
                    id: uuidv4(),
                    groupKey: templateInfo?.key || 'custom',
                    groupName: templateInfo?.name || 'カスタム項目'
                };
            });
            setFields(initialFields);

            const initialExpanded = initialFields.reduce((acc, field) => {
                acc[field.groupKey] = true;
                return acc;
            }, {});
            setExpandedGroups(initialExpanded);
        } else {
            setFields([]);
            setExpandedGroups({});
        }
    };

    useEffect(() => {
        if (Object.keys(worldFormData).length > 0) {
            const currentData = getCurrentState();
            const mergedData = { ...currentData, ...worldFormData };
            populateState(mergedData);
        }
    }, [worldFormData]);

    const getCurrentState = (): Partial<SettingItem> => ({ 
        name, 
        fields: fields.map(({ id, groupKey, groupName, ...rest }) => rest),
        longDescription, 
        memo, 
        exportDescription, 
        mapImageUrl 
    });

    const isDirty = useMemo(() => {
        if (!initialStateString) return false;
        const currentStateString = JSON.stringify(getCurrentState());
        return currentStateString !== initialStateString;
    }, [name, fields, longDescription, memo, exportDescription, mapImageUrl, initialStateString]);

    useEffect(() => {
        if (isOpen) {
            // itemToEditがnullまたは空オブジェクト（初期状態）の場合は新規作成とみなす
            const hasDataToEdit = itemToEdit && (itemToEdit.id || Object.keys(itemToEdit).length > 0);

            if (hasDataToEdit) {
                populateState(itemToEdit);
                useStore.getState().setFormData('world', itemToEdit);
            } else {
                resetFormData('world'); // ストアにある前回の残骸を消す
                populateState(initialEmptyWorldState);
            }

            setEditedFields(new Set());
            setActiveTab('profile');

            setTimeout(() => {
                const stateToSaveAsString = JSON.stringify(getCurrentState());
                setInitialStateString(stateToSaveAsString);
            }, 0);
        }
    }, [isOpen, itemToEdit, resetFormData]);

    const handleAddField = (groupKey = 'custom', groupName = 'カスタム項目') => {
        const newField: Field = { id: uuidv4(), key: '', value: '', groupKey, groupName };
        setFields([...fields, newField]);
    };

    const handleRemoveField = (id: string) => setFields(fields.filter(f => f.id !== id));
    const handleFieldChange = (id: string, prop: 'key' | 'value', value: string) => {
        setFields(fields.map(f => f.id === id ? { ...f, [prop]: value } : f));
        markEdited('fields');
    };

    const markEdited = (fieldKey: string) => {
        setEditedFields(prev => new Set(prev).add(fieldKey));
    };

    const handleApplyTemplate = (templateKey: keyof typeof worldTemplates) => {
        const templateExists = fields.some(f => f.groupKey === templateKey);
        if (templateExists) return; 

        const template = worldTemplates[templateKey];
        const newFields: Field[] = template.fields.map(f => ({
            id: uuidv4(),
            key: f.key,
            value: f.value || '',
            groupKey: templateKey,
            groupName: template.name
        }));
        setFields(prev => [...newFields, ...prev]);
        setExpandedGroups(prev => ({ ...prev, [templateKey]: true }));
        markEdited('fields');
    };

    const handleRemoveGroup = (groupKey: string) => {
        setFields(prev => prev.filter(f => f.groupKey !== groupKey));
        setExpandedGroups(prev => {
            const newExpanded = { ...prev };
            delete newExpanded[groupKey];
            return newExpanded;
        });
        markEdited('fields');
    };

    const handleMapImageUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
        const file = event.target.files?.[0];
        if (file) {
            const reader = new FileReader();
            reader.onloadend = async () => {
                const result = reader.result as string;
                const compressed = await compressImage(result);
                setMapImageUrl(compressed);
                markEdited('mapImageUrl');
            };
            reader.readAsDataURL(file);
        }
    };

    const handleSubmit = (e) => {
        e.preventDefault();
        if (!name.trim()) return;
        const stateToSave = getCurrentState();
        const finalFields = (stateToSave.fields || []).filter(f => f.key.trim() !== '');
        onSave({ ...itemToEdit, ...stateToSave, fields: finalFields, type: 'world' });
    };

    const handleKeyDown = (e: React.KeyboardEvent<HTMLFormElement>) => {
        if (e.key === 'Enter' && (e.ctrlKey || e.metaKey)) {
            e.preventDefault();
            (e.currentTarget as HTMLFormElement).requestSubmit();
        }
    };

    const handleCloseRequest = () => {
        if (isDirty) {
            setIsConfirmCloseOpen(true);
        } else {
            onClose();
        }
    };

    const handleSaveAndClose = () => {
        (document.getElementById('world-form') as HTMLFormElement)?.requestSubmit();
        setIsConfirmCloseOpen(false);
    };

    const handleOpenWorldGen = () => {
        const currentData = { name, fields: fields.filter(f => f.key.trim() || f.value.trim()) };
        const cleanedData: any = {};
        if (currentData.name.trim()) cleanedData.name = currentData.name.trim();
        const cleanedFields = currentData.fields.map(({id, groupKey, groupName, ...rest}) => rest).filter(f => f.key.trim() || f.value.trim());
        if(cleanedFields.length > 0) cleanedData.fields = cleanedFields;
        onOpenWorldGenModal(Object.keys(cleanedData).length > 0 ? cleanedData : null);
    };

    const TabButton = ({ tabId, label }: { tabId: string; label: React.ReactNode }) => (
        <button type="button" onClick={() => setActiveTab(tabId)} className={`px-4 py-2 text-sm font-medium transition-colors ${activeTab === tabId ? 'border-b-2 border-indigo-400 text-indigo-400' : 'border-b-2 border-transparent text-gray-400 hover:text-gray-200'}`}>
            {label}
        </button>
    );

    const renderLabel = (label: string, fieldKey?: string, helpNode?: React.ReactNode) => {
        const isAuto = itemToEdit?.isAutoFilled && fieldKey && !editedFields.has(fieldKey);
        return (
            <div className="flex items-center gap-2 mb-1">
                <label className="text-sm font-medium text-gray-400">{label}</label>
                {helpNode}
                {isAuto && (
                    <span className="text-[10px] bg-indigo-500/20 text-indigo-400 border border-indigo-500/50 px-1.5 py-0.5 rounded font-bold animate-pulse">補完済み</span>
                )}
            </div>
        );
    };

    const modalTitle = itemToEdit && (itemToEdit.id || Object.keys(itemToEdit).length > 0) ? '世界観を編集' : '世界観を新規作成';

    // Styles for mobile optimization
    const modalContainerClass = isMobile 
        ? "fixed inset-0 bg-gray-900 w-full h-[100dvh] flex flex-col z-[60]" 
        : "bg-gray-800 rounded-lg shadow-xl w-full max-w-4xl p-6 border border-gray-700 max-h-[90vh] flex flex-col";

    const inputClass = `w-full bg-gray-900 border border-gray-600 rounded-md px-3 py-2 text-white ${isMobile ? 'text-base' : 'text-sm'}`;
    const buttonClass = (colorClass: string) => `${colorClass} text-white rounded-md transition btn-pressable flex items-center justify-center gap-2 ${isMobile ? 'p-3 text-base w-full' : 'px-4 py-2 text-sm'}`;

    const renderFieldInput = (field: Field) => {
        const allTemplateFields = Object.values(worldTemplates).flatMap(t => t.fields);
        const templateField = allTemplateFields.find(f => f.key === field.key);

        if (templateField && templateField.type === 'select') {
            const isCustom = !templateField.options.includes(field.value);
            return (
                 <div className={`flex gap-2 ${isMobile ? 'flex-col' : 'items-center'}`}>
                    <select 
                        value={isCustom ? 'その他' : field.value}
                        onChange={e => handleFieldChange(field.id, 'value', e.target.value)}
                        className={`${isMobile ? 'w-full' : 'w-1/2'} ${inputClass}`}
                    >
                        {templateField.options.map(opt => <option key={opt} value={opt}>{opt}</option>)}
                    </select>
                    {(isCustom || field.value === 'その他') && (
                        <input
                            type="text"
                            value={isCustom ? field.value : ''}
                            onChange={e => handleFieldChange(field.id, 'value', e.target.value)}
                            placeholder="内容を自由入力"
                            className={`${isMobile ? 'w-full' : 'w-1/2'} ${inputClass}`}
                            autoFocus
                        />
                    )}
                 </div>
            );
        }
        if (templateField && templateField.type === 'textarea') {
            return <textarea value={field.value} onChange={e => handleFieldChange(field.id, 'value', e.target.value)} placeholder={templateField.placeholder} rows={3} className={`${inputClass} resize-y`}/>
        }
        return <input type="text" value={field.value} onChange={e => handleFieldChange(field.id, 'value', e.target.value)} placeholder={templateField?.placeholder || '内容（例：ギル）'} className={inputClass}/>;
    };

    const groupedFields = useMemo(() => {
        return fields.reduce((acc, field) => {
            const key = field.groupKey || 'custom';
            if (!acc[key]) {
                acc[key] = { name: field.groupName || 'カスタム項目', items: [] };
            }
            acc[key].items.push(field);
            return acc;
        }, {} as Record<string, { name: string; items: Field[] }>);
    }, [fields]);

    const groupOrder = ['place', 'organization', 'magic_tech', 'event', 'item'];
    const isAiAssistantDisabled = fields.length === 0;

    return (
        <div className={isMobile ? "fixed inset-0 z-[60]" : "fixed inset-0 bg-black/60 backdrop-blur-sm flex justify-center items-center z-50"}>
             <div className={modalContainerClass}>
                <UnsavedChangesPopover isOpen={isConfirmCloseOpen} targetRef={closeButtonRef} onCancel={() => setIsConfirmCloseOpen(false)} onCloseWithoutSaving={onClose} onSaveAndClose={handleSaveAndClose} />

                <div className={`flex justify-between items-center flex-shrink-0 ${isMobile ? 'p-4 border-b border-gray-700' : 'mb-4'}`}>
                    <h2 className={`font-bold text-indigo-400 flex items-center gap-2 ${isMobile ? 'text-lg' : 'text-xl'}`}><Icons.GlobeIcon />{modalTitle}</h2>
                    <div className="flex items-center gap-2">
                        <button type="button" onClick={onShowHelp} className="p-2 rounded-full hover:bg-gray-700 transition"><Icons.HelpCircleIcon className="h-5 w-5 text-white" /></button>
                        <button ref={closeButtonRef} type="button" onClick={handleCloseRequest} className="p-2 rounded-full hover:bg-gray-700 transition"><Icons.XIcon /></button>
                    </div>
                </div>

                <div className={`flex border-b border-gray-700 mb-6 flex-shrink-0 ${isMobile ? 'overflow-x-auto' : ''}`}>
                    <TabButton tabId="profile" label="基本設定" />
                    <TabButton tabId="visual" label="ビジュアル" />
                    <TabButton tabId="ai_settings" label="AI設定" />
                </div>

                <form id="world-form" onSubmit={handleSubmit} onKeyDown={handleKeyDown} className={`flex-grow overflow-y-auto min-h-0 ${isMobile ? 'px-4 pb-24' : 'pr-2'}`}>
                    <div className="space-y-6">
                         {activeTab === 'profile' && (
                             <div className="space-y-6">
                                <div>
                                    {renderLabel("名前 *", "name")}
                                    <input type="text" value={name} onChange={e => { setName(e.target.value); markEdited('name'); }} className={inputClass} required />
                                </div>
                                <div>
                                    <label className="text-sm font-medium text-gray-400 mb-2 block">テンプレートから項目を選択</label>
                                    <div className="flex gap-2 flex-wrap">
                                        {Object.entries(worldTemplates).map(([key, template]) => (
                                            <button 
                                                key={key}
                                                type="button" 
                                                onClick={() => handleApplyTemplate(key as keyof typeof worldTemplates)} 
                                                className={`text-sm bg-gray-700 text-white rounded-md hover:bg-gray-600 transition disabled:opacity-50 ${isMobile ? 'py-2 px-4' : 'px-3 py-1'}`}
                                                disabled={!!groupedFields[key]}
                                            >
                                                {template.name}
                                            </button>
                                        ))}
                                    </div>
                                </div>

                                <div className="space-y-4">
                                    {groupOrder.map(key => {
                                        const group = groupedFields[key];
                                        if (!group) return null;
                                        const isExpanded = expandedGroups[key];
                                        return (
                                            <div key={key} className="bg-gray-900/50 rounded-lg">
                                                <div className="flex justify-between items-center p-2 cursor-pointer" onClick={() => setExpandedGroups(p => ({ ...p, [key]: !p[key] }))}>
                                                    <div className="flex items-center gap-2 min-w-0">
                                                        <div className="flex items-center gap-2 flex-shrink-0">
                                                            <h3 className="text-md font-semibold text-gray-300 whitespace-nowrap">{group.name}</h3>
                                                        </div>
                                                        {!isExpanded && (
                                                            <div className="text-xs text-gray-400 truncate">
                                                                {group.items.map(f => f.key).join(' / ')}
                                                            </div>
                                                        )}
                                                    </div>
                                                    <button type="button" onClick={(e) => { e.stopPropagation(); handleRemoveGroup(key); }} className="p-1 text-gray-500 hover:text-red-400 flex-shrink-0 ml-2"><Icons.TrashIcon /></button>
                                                </div>
                                                {isExpanded && (
                                                    <div className="p-4 pt-2 border-t border-gray-700/50 space-y-3">
                                                        {group.items.map((field) => (
                                                            <div key={field.id}>
                                                                <label className="text-sm font-medium text-gray-400 mb-1 block">{field.key}</label>
                                                                {renderFieldInput(field)}
                                                            </div>
                                                        ))}
                                                    </div>
                                                )}
                                            </div>
                                        );
                                    })}
                                </div>

                                <div className="space-y-3 pt-4 border-t border-gray-700/50">
                                    <h3 className="text-lg font-semibold text-gray-300">カスタム項目</h3>
                                    {(groupedFields['custom']?.items || []).map((field) => (
                                        <div key={field.id} className="flex flex-col gap-2 pb-4 border-b border-gray-700/30 last:border-0">
                                            <div className="flex items-center gap-2">
                                                <input type="text" value={field.key} onChange={e => handleFieldChange(field.id, 'key', e.target.value)} placeholder="項目名（例：通貨）" className={`flex-1 ${inputClass}`}/>
                                                <button type="button" onClick={() => handleRemoveField(field.id)} className={`text-gray-500 hover:text-red-400 transition flex-shrink-0 ${isMobile ? 'p-3' : 'p-2'}`}><Icons.TrashIcon/></button>
                                            </div>
                                            {renderFieldInput(field)}
                                        </div>
                                    ))}
                                    <button type="button" onClick={() => handleAddField()} className={`w-full text-indigo-400 border-2 border-dashed border-gray-600 rounded-md hover:bg-gray-700/50 ${isMobile ? 'py-3 text-base' : 'py-1 text-sm'}`}>項目を追加</button>
                                </div>
                            </div>
                         )}

                         {activeTab === 'visual' && (
                             <div className="space-y-6">
                                <h3 className="text-lg font-semibold text-gray-300">地図・イメージ画像</h3>
                                <div>
                                    {renderLabel("画像URL", "mapImageUrl")}
                                    <input type="text" value={(mapImageUrl || '').startsWith('data:') ? '' : (mapImageUrl || '')} onChange={e => { setMapImageUrl(e.target.value); markEdited('mapImageUrl'); }} placeholder="https://..." className={inputClass}/>
                                </div>

                                <label className={`w-full flex items-center justify-center gap-2 text-indigo-300 border-2 border-dashed border-gray-600 rounded-lg hover:bg-gray-700/50 hover:border-indigo-500 cursor-pointer transition btn-pressable ${isMobile ? 'py-4 text-base' : 'py-2 text-sm'}`}>
                                    <input type="file" onChange={handleMapImageUpload} accept="image/*" className="hidden" />
                                    <Icons.UploadCloudIcon className="h-5 w-5" />
                                    <span>またはファイルを選択</span>
                                </label>
                                <div className="w-full aspect-video rounded-md bg-gray-900/50 flex items-center justify-center overflow-hidden relative">
                                    {mapImageUrl ? (
                                        <>
                                            <img src={mapImageUrl} alt="Map preview" className="object-contain w-full h-full" />
                                            <div className="absolute top-2 right-2 flex flex-col space-y-2">
                                                <button type="button" onClick={(e) => { e.stopPropagation(); setIsMapViewerOpen(true); }} className="p-2 bg-black/50 rounded-md text-white hover:bg-black/75 transition" title="拡大表示"><Icons.ExpandIcon className="h-5 w-5" /></button>
                                                <button type="button" onClick={(e) => { e.stopPropagation(); setMapImageUrl(''); markEdited('mapImageUrl'); }} className="p-2 bg-black/50 rounded-md text-white hover:bg-red-500/75 transition" title="画像を削除"><Icons.TrashIcon className="h-5 w-5" /></button>
                                            </div>
                                        </>
                                    ) : (
                                        <p className="text-gray-500">画像がありません</p>
                                    )}
                                </div>
                            </div>
                         )}

                         {activeTab === 'ai_settings' && (
                             <div className="space-y-6">
                                <div>
                                    {renderLabel("詳細設定 (AIが参照)", "longDescription", <Icons.BotIcon className="h-4 w-4 text-indigo-400" />)}
                                    <p className="text-xs text-gray-400 mb-2">物語の歴史、文化、地理、物理法則など、AIに記憶させておきたい情報を入力してください。</p>
                                    <textarea value={longDescription} onChange={e => { setLongDescription(e.target.value); markEdited('longDescription'); }} rows={8} className={`${inputClass} resize-y`}/>
                                </div>
                                <div>
                                    {renderLabel("メモ (AIは非参照)", "memo", <Icons.PenSquareIcon className="h-4 w-4 text-lime-400" />)}
                                    <p className="text-xs text-gray-400 mb-2">あなた専用のメモ欄です。</p>
                                    <textarea value={memo} onChange={e => { setMemo(e.target.value); markEdited('memo'); }} rows={5} className={`${inputClass} resize-y`}/>
                                </div>
                                <div>
                                    {renderLabel("書き出し用説明文", "exportDescription", <Icons.BookIcon className="h-4 w-4 text-orange-400" />)}
                                    <p className="text-xs text-gray-400 mb-2">HTML書き出し時に表示される説明文です。</p>
                                    <textarea value={exportDescription} onChange={e => { setExportDescription(e.target.value); markEdited('exportDescription'); }} rows={5} className={`${inputClass} resize-y`}/>
                                </div>
                            </div>
                         )}
                    </div>
                </form>

                <div className={`mt-auto border-t border-gray-700 pt-4 bg-gray-900/50 ${isMobile ? 'flex flex-col gap-3 px-4' : 'flex justify-between items-center mt-6'}`} style={isMobile ? { paddingBottom: 'calc(1rem + env(safe-area-inset-bottom))' } : {}}>
                    <div ref={aiAssistantHelpRef} onMouseEnter={() => isAiAssistantDisabled && setIsAiAssistantHelpOpen(true)} onMouseLeave={() => setIsAiAssistantHelpOpen(false)} className={isMobile ? 'w-full order-1' : ''}>
                        <button type="button" onClick={handleOpenWorldGen} disabled={isAiAssistantDisabled} className={`flex items-center justify-center gap-2 font-semibold btn-pressable bg-teal-600 text-white hover:bg-teal-500 disabled:bg-gray-600 disabled:cursor-not-allowed ${isMobile ? 'w-full py-3 rounded-md text-base' : 'px-4 py-2 text-sm rounded-md transition'}`}><Icons.MoonIcon className={isMobile ? "h-5 w-5" : "h-4 w-4"} /><span>AIアシスタント</span></button>
                    </div>
                    <div className={`flex gap-3 ${isMobile ? 'flex-col w-full order-2' : ''}`}>
                        <button type="button" onClick={handleCloseRequest} className={buttonClass('bg-gray-600 hover:bg-gray-500')}><Icons.XIcon className="h-4 w-4" />キャンセル</button>
                        <button type="submit" form="world-form" data-testid="modal-save-button" className={buttonClass('bg-indigo-600 hover:bg-indigo-500 font-bold')}><Icons.CheckIcon className="h-4 w-4" />保存</button>
                    </div>
                </div>
            </div>
            {isMapViewerOpen && <MapViewerModal imageUrl={mapImageUrl} onClose={() => setIsMapViewerOpen(false)} />}
        </div>
    );
};

import React, { useState, useEffect, useRef, useMemo } from 'react';
import * as Icons from '../../icons';
import { SettingItem } from '../../types';
import { NameGenerator } from '../NameGenerator';
import * as utilityApi from '../../utilityApi';
import { UnsavedChangesPopover } from '../UnsavedChangesPopover';
import { HelpPopover } from '../HelpPopover';
import { useStore } from '../../store/index';
import { compressImage } from '../../utils';

interface CharacterFormProps {
    isOpen: boolean;
    onClose: () => void;
    onSave: (item: any) => void;
    itemToEdit: SettingItem | null;
    allSettings: SettingItem[];
    onOpenCharacterGenModal: (data: Partial<SettingItem> | null) => void;
    onOpenImageGenModal: () => void;
    onShowHelp: () => void;
    isMobile?: boolean;
}

export const CharacterForm: React.FC<CharacterFormProps> = ({
    isOpen,
    onClose,
    onSave,
    itemToEdit,
    allSettings,
    onOpenCharacterGenModal,
    onOpenImageGenModal,
    onShowHelp,
    isMobile = false,
}) => {
    // Local form state
    const [name, setName] = useState('');
    const [appearance, setAppearance] = useState<{ imageUrl: string; traits: { key: string; value: string }[] }>({ imageUrl: '', traits: [] });
    const [furigana, setFurigana] = useState('');
    const [gender, setGender] = useState('');
    const [age, setAge] = useState('');
    const [species, setSpecies] = useState('');
    const [firstPersonPronoun, setFirstPersonPronoun] = useState('');
    const [personality, setPersonality] = useState('');
    const [speechPattern, setSpeechPattern] = useState('');
    const [secret, setSecret] = useState('');
    const [themeColor, setThemeColor] = useState('');
    const [longDescription, setLongDescription] = useState('');
    const [memo, setMemo] = useState('');
    const [exportDescription, setExportDescription] = useState('');
    const [originSelection, setOriginSelection] = useState('');
    const [customOriginValue, setCustomOriginValue] = useState('');
    const [affiliationSelection, setAffiliationSelection] = useState('');
    const [customAffiliationValue, setCustomAffiliationValue] = useState('');

    const [activeTab, setActiveTab] = useState('profile');
    const [isNameGeneratorOpen, setIsNameGeneratorOpen] = useState(false);
    const [isConfirmCloseOpen, setIsConfirmCloseOpen] = useState(false);
    const [initialStateString, setInitialStateString] = useState('');
    const closeButtonRef = useRef(null);
    const originHelpRef = useRef(null);
    const [isOriginHelpOpen, setIsOriginHelpOpen] = useState(false);
    const affiliationHelpRef = useRef(null);
    const [isAffiliationHelpOpen, setIsAffiliationHelpOpen] = useState(false);

    // フィールドごとの変更済みフラグ
    const [editedFields, setEditedFields] = useState<Set<string>>(new Set());

    // Subscribe to external form data changes from AI modal
    const characterFormData = useStore(state => state.characterFormData);
    const resetFormData = useStore(state => state.resetFormData);

    const organizationOptions = useMemo(() => {
        if (!allSettings) return [];
        return allSettings.filter(item =>
            item.type === 'world' &&
            item.fields?.some(f => f.key === '種別' && ['国家', 'ギルド', '秘密結社', '企業'].includes(f.value))
        );
    }, [allSettings]);

    const locationOptions = useMemo(() => {
        if (!allSettings) return [];
        const organizationIds = new Set(organizationOptions.map(org => org.id));
        return allSettings.filter(item => item.type === 'world' && !organizationIds.has(item.id));
    }, [allSettings, organizationOptions]);


    const populateState = (data) => {
        if (!data) return;

        setName(data.name || '');
        setAppearance(data.appearance || { imageUrl: '', traits: [] });
        setFurigana(data.furigana || '');
        setGender(data.gender || '');
        setAge(data.age || '');
        setSpecies(data.species || '');
        setFirstPersonPronoun(data.firstPersonPronoun || '');
        setPersonality(data.personality || '');
        setSpeechPattern(data.speechPattern || '');
        setSecret(data.secret || '');
        setThemeColor(data.themeColor || '');
        setLongDescription(data.longDescription || '');
        setMemo(data.memo || '');
        setExportDescription(data.exportDescription || '');

        const initialOrigin = data.origin || '';
        const isStandardOrigin = locationOptions.some(o => o.name === initialOrigin);
        if (isStandardOrigin) {
            setOriginSelection(initialOrigin);
            setCustomOriginValue('');
        } else if (initialOrigin) {
            setOriginSelection('その他');
            setCustomOriginValue(initialOrigin);
        } else {
            setOriginSelection('');
            setCustomOriginValue('');
        }

        const initialAffiliation = data.affiliation || '';
        const isStandardAffiliation = organizationOptions.some(o => o.name === initialAffiliation);
        if (isStandardAffiliation) {
            setAffiliationSelection(initialAffiliation);
            setCustomAffiliationValue('');
        } else if (initialAffiliation) {
            setAffiliationSelection('その他');
            setCustomAffiliationValue(initialAffiliation);
        } else {
            setAffiliationSelection('');
            setCustomAffiliationValue('');
        }
    };

    useEffect(() => {
        if (Object.keys(characterFormData).length > 0) {
            const currentData = getCurrentState();
            const mergedData = { ...currentData, ...characterFormData };
            populateState(mergedData);
        }
    }, [characterFormData]);

    const getCurrentState = (): Partial<SettingItem> => {
        const finalOrigin = originSelection === 'その他' ? customOriginValue : originSelection;
        const finalAffiliation = affiliationSelection === 'その他' ? customAffiliationValue : affiliationSelection;
        return { name, furigana, gender, age, species, firstPersonPronoun, personality, origin: finalOrigin, affiliation: finalAffiliation, speechPattern, secret, themeColor, longDescription, memo, exportDescription, appearance };
    };

    const isDirty = useMemo(() => {
        if (!initialStateString) return false;
        return JSON.stringify(getCurrentState()) !== initialStateString;
    }, [name, furigana, gender, age, species, firstPersonPronoun, personality, originSelection, customOriginValue, affiliationSelection, customAffiliationValue, speechPattern, secret, themeColor, longDescription, memo, exportDescription, appearance, initialStateString]);

    useEffect(() => {
        if (isOpen) {
            // itemToEditがnullまたは空オブジェクト（初期状態）の場合は新規作成とみなす
            const hasDataToEdit = itemToEdit && (itemToEdit.id || Object.keys(itemToEdit).length > 0);

            if (hasDataToEdit) {
                populateState(itemToEdit);
                useStore.getState().setFormData('character', itemToEdit);
            } else {
                resetFormData('character'); // ストアにある前回の残骸を消す
                const initialData = {
                    name: '',
                    appearance: { imageUrl: '', traits: [] },
                    furigana: '',
                    gender: '',
                    age: '',
                    species: '',
                    firstPersonPronoun: '',
                    personality: '',
                    origin: '',
                    affiliation: '',
                    speechPattern: '',
                    secret: '',
                    themeColor: '',
                    longDescription: '',
                    memo: '',
                    exportDescription: '',
                };
                populateState(initialData);
            }

            setEditedFields(new Set());
            setActiveTab('profile');

            setTimeout(() => {
                setInitialStateString(JSON.stringify(getCurrentState()));
            }, 0);
        }
    }, [isOpen, itemToEdit, resetFormData]);

    useEffect(() => {
      if (!isMobile) return;
      const setVh = () => {
        document.documentElement.style.setProperty('--vh', `${window.innerHeight * 0.01}px`);
      };
      setVh();
      window.addEventListener('resize', setVh);
      return () => window.removeEventListener('resize', setVh);
    }, [isMobile]);

    const handleImageUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
        const file = event.target.files?.[0];
        if (file) {
            const reader = new FileReader();
            reader.onloadend = async () => {
                const result = reader.result as string;
                const compressed = await compressImage(result);
                setAppearance(prev => ({ ...prev, imageUrl: compressed }));
                markEdited('imageUrl');
            };
            reader.readAsDataURL(file);
        }
    };

    const handleAddTrait = () => setAppearance(prev => ({ ...prev, traits: [...(prev?.traits || []), { key: '', value: '' }] }));
    const handleRemoveTrait = (index) => setAppearance(prev => ({ ...prev, traits: (prev?.traits || []).filter((_, i) => i !== index) }));
    const handleTraitChange = (index, prop, value) => { 
        const newTraits = [...(appearance?.traits || [])]; 
        newTraits[index][prop] = value; 
        setAppearance(prev => ({ ...prev, traits: newTraits })); 
        markEdited('traits');
    };

    const markEdited = (fieldName: string) => {
        setEditedFields(prev => new Set(prev).add(fieldName));
    };

    const handleSubmit = (e) => {
        e.preventDefault();
        if (!name.trim()) return;

        const characterData = {
            ...itemToEdit,
            ...getCurrentState(),
            type: 'character',
            appearance: { ...(appearance || {}), traits: (appearance?.traits || []).filter(t => t.key.trim() !== '') },
        };
        onSave(characterData);
    };

    const handleKeyDown = (e: React.KeyboardEvent<HTMLFormElement>) => {
        if (e.key === 'Enter' && (e.ctrlKey || e.metaKey)) {
            e.preventDefault();
            (e.currentTarget as HTMLFormElement).requestSubmit();
        }
    };

    const handleCloseRequest = () => {
        if (isDirty) {
            setIsConfirmCloseOpen(true);
        } else {
            onClose();
        }
    };

    const handleSaveAndClose = () => {
        (document.getElementById('character-form') as HTMLFormElement)?.requestSubmit();
        setIsConfirmCloseOpen(false);
    };

    const handleOpenCharacterGen = () => {
        const currentData = getCurrentState();
         const cleanedData: Partial<SettingItem> = Object.fromEntries(
            Object.entries(currentData).filter(([_, v]) => {
                if (typeof v === 'string') return v.trim() !== '';
                if (Array.isArray(v)) return v.length > 0;
                if (typeof v === 'object' && v !== null) { // for appearance
                    return (v.imageUrl && v.imageUrl.trim() !== '') || (v.traits && v.traits.length > 0);
                }
                return false;
            })
        );
        onOpenCharacterGenModal(Object.keys(cleanedData).length > 0 ? cleanedData : null);
    };

    const characterKeywords = useMemo(() => {
        const keywords = [
            species,
            personality,
            gender,
            ...(appearance?.traits || []).map(t => t.value)
        ];
        return keywords.filter(Boolean).join(', ');
    }, [species, personality, gender, appearance?.traits]);

    const handleGenerateNames = async (category: string, keywords: string): Promise<string[]> => {
        const result = await utilityApi.generateNames({ category, keywords });
        if (result.success === false) {
            alert(`名前の生成に失敗しました: ${result.error.message}`);
            return [];
        }
        return result.data;
    };

    const TabButton = ({ tabId, label }: { tabId: string; label: React.ReactNode }) => (
        <button type="button" onClick={() => setActiveTab(tabId)} className={`px-4 py-2 text-sm font-medium transition-colors ${activeTab === tabId ? 'border-b-2 border-indigo-400 text-indigo-400' : 'border-b-2 border-transparent text-gray-400 hover:text-gray-200'}`}>
            {label}
        </button>
    );

    const handleOriginSelectChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
        setOriginSelection(e.target.value);
        if (e.target.value !== 'その他') setCustomOriginValue('');
        markEdited('origin');
    };

    const handleAffiliationSelectChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
        setAffiliationSelection(e.target.value);
        if (e.target.value !== 'その他') setCustomAffiliationValue('');
        markEdited('affiliation');
    };

    const renderLabel = (label: string, fieldKey?: string, helpNode?: React.ReactNode) => {
        const isAuto = itemToEdit?.isAutoFilled && fieldKey && !editedFields.has(fieldKey);
        return (
            <div className="flex items-center justify-between mb-1">
                <div className="flex items-center gap-2">
                    <label className="text-sm font-medium text-gray-400">{label}</label>
                    {helpNode}
                    {isAuto && (
                        <span className="text-[10px] bg-indigo-500/20 text-indigo-400 border border-indigo-500/50 px-1.5 py-0.5 rounded font-bold animate-pulse">補完済み</span>
                    )}
                </div>
            </div>
        );
    };

    const modalTitle = itemToEdit && (itemToEdit.id || Object.keys(itemToEdit).length > 0) ? 'キャラクターを編集' : 'キャラクターを新規作成';
    const imageUrlValue = appearance?.imageUrl ?? '';

    // Styles for mobile optimization
    const modalContainerClass = isMobile 
    ? "bg-gray-900 w-full h-[100dvh] flex flex-col min-h-0 z-[60]" 
    : "bg-gray-800 rounded-lg shadow-xl w-full max-w-4xl border border-gray-700 max-h-[90vh] flex flex-col min-h-0 overflow-hidden";

    const inputClass = `w-full bg-gray-900 border border-gray-600 rounded-md px-3 py-2 text-white ${isMobile ? 'text-base' : 'text-sm'}`;
    const buttonClass = (colorClass: string) => `${colorClass} text-white rounded-md transition btn-pressable flex items-center justify-center gap-2 ${isMobile ? 'p-3 text-base w-full' : 'px-4 py-2 text-sm'}`;

    return (
        <div className={isMobile ? "fixed inset-0 z-[60]" : "fixed inset-0 bg-black/60 backdrop-blur-sm flex justify-center items-center z-50"}>
            <div className={modalContainerClass}>
                <UnsavedChangesPopover isOpen={isConfirmCloseOpen} targetRef={closeButtonRef} onCancel={() => setIsConfirmCloseOpen(false)} onCloseWithoutSaving={onClose} onSaveAndClose={handleSaveAndClose} />

                <div className={`flex justify-between items-center flex-shrink-0 ${isMobile ? 'p-4 border-b border-gray-700' : 'p-6 pb-0 mb-4'}`}>
                    <h2 className={`font-bold text-indigo-400 flex items-center gap-2 ${isMobile ? 'text-lg' : 'text-xl'}`}><Icons.UserPlusIcon />{modalTitle}</h2>
                    <div className="flex items-center gap-2">
                        <button type="button" onClick={onShowHelp} className="p-2 rounded-full hover:bg-gray-700 transition"><Icons.HelpCircleIcon className="h-5 w-5 text-white" /></button>
                        <button ref={closeButtonRef} type="button" onClick={handleCloseRequest} className="p-2 rounded-full hover:bg-gray-700 transition"><Icons.XIcon /></button>
                    </div>
                </div>

                <div className={`flex border-b border-gray-700 mb-6 flex-shrink-0 ${isMobile ? 'overflow-x-auto' : 'px-6'}`}>
                    <TabButton tabId="profile" label="プロフィール" />
                    <TabButton tabId="personality" label="性格・内面" />
                    <TabButton tabId="ai_settings" label="AI設定" />
                </div>

                <form id="character-form" onSubmit={handleSubmit} onKeyDown={handleKeyDown} className={`flex-grow overflow-y-auto min-h-0 ${isMobile ? 'px-4 pb-4' : 'px-6 py-2'}`}>
                    <div className="space-y-6">
                        {activeTab === 'profile' && (
                            <div className={`grid ${isMobile ? 'grid-cols-1 gap-6' : 'grid-cols-1 md:grid-cols-3 gap-6'}`}>
                                <div className={`space-y-4 ${isMobile ? 'order-first' : 'md:col-span-1'}`}>
                                    <div>
                                        {renderLabel("画像", "imageUrl")}
                                        {imageUrlValue ? (
                                            <div className="w-[60%] aspect-square rounded-md overflow-hidden mx-auto border border-gray-600">
                                                <img src={imageUrlValue} alt="Character" className="object-cover object-top w-full h-full" />
                                            </div>
                                        ) : (
                                            <div className="w-[60%] aspect-square flex items-center justify-center bg-gray-700 text-gray-500 text-sm font-bold rounded-md mx-auto border border-gray-600">
                                                NO IMAGE
                                            </div>
                                        )}
                                    </div>
                                    <input type="text" value={imageUrlValue.startsWith('data:') ? '' : imageUrlValue} onChange={e => { setAppearance(prev => ({ ...prev, imageUrl: e.target.value })); markEdited('imageUrl'); }} placeholder="画像URL..." className={inputClass} />
                                    <div className="space-y-3">
                                        <label className={`w-full flex items-center justify-center gap-2 border-2 border-dashed border-gray-600 rounded-lg hover:bg-gray-700/50 hover:border-indigo-500 cursor-pointer transition btn-pressable text-indigo-300 ${isMobile ? 'py-3' : 'py-1.5 text-sm'}`}>
                                            <input type="file" onChange={handleImageUpload} accept="image/*" className="hidden" />
                                            <Icons.UploadCloudIcon className="h-5 w-5" />
                                            <span>ファイルを選択</span>
                                        </label>
                                        <button type="button" onClick={onOpenImageGenModal} className={`w-full flex items-center justify-center gap-2 border-2 border-dashed border-gray-600 rounded-lg transition btn-pressable text-teal-300 hover:bg-gray-700/50 hover:border-teal-500 ${isMobile ? 'py-3' : 'py-1.5 text-sm'}`}>
                                            <Icons.MoonIcon className="h-5 w-5" />
                                            <span className="text-teal-400">AIで立ち絵を生成</span>
                                        </button>
                                    </div>
                                    <div>
                                        {renderLabel("テーマカラー", "themeColor")}
                                        <div className="flex items-center gap-2">
                                            <input type="color" value={themeColor || '#ffffff'} onChange={e => { setThemeColor(e.target.value); markEdited('themeColor'); }} className="w-full h-10 p-1 bg-gray-900 border border-gray-600 rounded-md cursor-pointer flex-grow" />
                                            <button type="button" onClick={() => { setThemeColor(''); markEdited('themeColor'); }} className="w-12 h-10 flex items-center justify-center bg-gray-700 text-gray-400 rounded-md hover:opacity-75 transition btn-pressable flex-shrink-0"><Icons.EraserIcon className="h-5 w-5" /></button>
                                        </div>
                                    </div>
                                </div>

                                <div className={`space-y-6 ${isMobile ? '' : 'md:col-span-2'}`}>
                                    <div className={`grid ${isMobile ? 'grid-cols-1 gap-4' : 'grid-cols-1 md:grid-cols-2 gap-x-6 gap-y-4'}`}>
                                         <div className={isMobile ? "" : "md:col-span-2"}>
                                            {renderLabel("名前 *", "name")}
                                            <div className="flex items-center gap-2">
                                                <input type="text" value={name} onChange={e => { setName(e.target.value); markEdited('name'); }} className={inputClass} required />
                                                <button type="button" onClick={() => setIsNameGeneratorOpen(true)} className={`flex-shrink-0 text-gray-400 hover:text-indigo-400 bg-gray-900 border border-gray-600 rounded-md ${isMobile ? 'p-3' : 'p-2'}`}><Icons.DiceIcon className="h-5 w-5"/></button>
                                            </div>
                                        </div>
                                        <div>{renderLabel("ふりがな", "furigana")}<input type="text" value={furigana} onChange={e => { setFurigana(e.target.value); markEdited('furigana'); }} className={inputClass}/></div>
                                        <div>{renderLabel("性別", "gender")}<input type="text" value={gender} onChange={e => { setGender(e.target.value); markEdited('gender'); }} className={inputClass}/></div>
                                        <div>{renderLabel("年齢", "age")}<input type="text" value={age} onChange={e => { setAge(e.target.value); markEdited('age'); }} className={inputClass}/></div>
                                        <div>{renderLabel("種族", "species")}<input type="text" value={species} onChange={e => { setSpecies(e.target.value); markEdited('species'); }} className={inputClass}/></div>
                                         <div className={isMobile ? "" : "md:col-span-1"}>
                                            {renderLabel("出身地", "origin", <button type="button" ref={originHelpRef} onMouseEnter={() => setIsOriginHelpOpen(true)} onMouseLeave={() => setIsOriginHelpOpen(false)} className="focus:outline-none"><Icons.HelpCircleIcon className="h-4 w-4 text-gray-500 hover:text-white" /></button>)}
                                            <select value={originSelection} onChange={handleOriginSelectChange} className={inputClass}>
                                                <option value="">未設定</option>
                                                {locationOptions.map(loc => (<option key={loc.id} value={loc.name}>{loc.name}</option>))}
                                                <option value="その他">その他（自由記入）</option>
                                            </select>
                                            {originSelection === 'その他' && <input type="text" value={customOriginValue} onChange={e => { setCustomOriginValue(e.target.value); markEdited('origin'); }} placeholder="内容..." className={`${inputClass} mt-2`} autoFocus />}
                                        </div>
                                        <div className={isMobile ? "" : "md:col-span-1"}>
                                            {renderLabel("所属組織", "affiliation", <button type="button" ref={affiliationHelpRef} onMouseEnter={() => setIsAffiliationHelpOpen(true)} onMouseLeave={() => setIsAffiliationHelpOpen(false)} className="focus:outline-none"><Icons.HelpCircleIcon className="h-4 w-4 text-gray-500 hover:text-white" /></button>)}
                                            <select value={affiliationSelection} onChange={handleAffiliationSelectChange} className={inputClass}>
                                                <option value="">未設定</option>
                                                {organizationOptions.map(org => (<option key={org.id} value={org.name}>{org.name}</option>))}
                                                <option value="その他">その他（自由記入）</option>
                                            </select>
                                            {affiliationSelection === 'その他' && <input type="text" value={customAffiliationValue} onChange={e => { setCustomAffiliationValue(e.target.value); markEdited('affiliation'); }} placeholder="内容..." className={`${inputClass} mt-2`} autoFocus />}
                                        </div>
                                    </div>
                                    <div className="space-y-3">
                                        {renderLabel("容姿特徴リスト", "traits")}
                                        {(appearance?.traits || []).map((trait, index) => (
                                            <div key={index} className="flex items-center gap-2">
                                                <input type="text" value={trait.key} onChange={e => handleTraitChange(index, 'key', e.target.value)} placeholder="項目" className={`w-1/3 ${inputClass}`}/>
                                                <input type="text" value={trait.value} onChange={e => handleTraitChange(index, 'value', e.target.value)} placeholder="内容" className={`flex-grow ${inputClass}`}/>
                                                <button type="button" onClick={() => handleRemoveTrait(index)} className={`text-gray-500 hover:text-red-400 transition flex-shrink-0 ${isMobile ? 'p-3' : 'p-2'}`}><Icons.TrashIcon/></button>
                                            </div>
                                        ))}
                                        <button type="button" onClick={handleAddTrait} className={`w-full text-indigo-400 border-2 border-dashed border-gray-600 rounded-md hover:bg-gray-700/50 ${isMobile ? 'py-3 text-base' : 'py-1 text-sm'}`}>特徴を追加</button>
                                    </div>
                                </div>
                            </div>
                        )}
                        {activeTab === 'personality' && ( 
                            <div className="space-y-6">
                                <div>{renderLabel("一人称", "firstPersonPronoun")}<input type="text" value={firstPersonPronoun} onChange={e => { setFirstPersonPronoun(e.target.value); markEdited('firstPersonPronoun'); }} placeholder="例：私、僕" className={inputClass}/></div>
                                <div>{renderLabel("性格", "personality")}<textarea value={personality} onChange={e => { setPersonality(e.target.value); markEdited('personality'); }} rows={6} className={`${inputClass} resize-y`} /></div>
                                <div>{renderLabel("話し方", "speechPattern")}<textarea value={speechPattern} onChange={e => { setSpeechPattern(e.target.value); markEdited('speechPattern'); }} rows={4} className={`${inputClass} resize-y`} /></div>
                                <div>{renderLabel("秘密", "secret")}<textarea value={secret} onChange={e => { setSecret(e.target.value); markEdited('secret'); }} rows={4} className={`${inputClass} resize-y`} /></div>
                            </div>
                        )}
                        {activeTab === 'ai_settings' && (
                            <div className="space-y-6">
                                <div>{renderLabel("詳細設定 (AIが参照)", "longDescription")}<textarea value={longDescription} onChange={e => { setLongDescription(e.target.value); markEdited('longDescription'); }} rows={8} className={`${inputClass} resize-y`} /></div>
                                <div>{renderLabel("メモ (AIは非参照)", "memo")}<textarea value={memo} onChange={e => { setMemo(e.target.value); markEdited('memo'); }} rows={5} className={`${inputClass} resize-y`} /></div>
                                <div>{renderLabel("書き出し用説明文", "exportDescription")}<textarea value={exportDescription} onChange={e => { setExportDescription(e.target.value); markEdited('exportDescription'); }} rows={5} className={`${inputClass} resize-y`} /></div>
                            </div>
                        )}
                    </div>
                </form>

                <div className={`border-t border-gray-700 bg-gray-900/50 flex-shrink-0 ${isMobile ? 'flex flex-col gap-3 px-4 pt-4' : 'flex justify-between items-center px-6 py-4'}`} style={isMobile ? { paddingBottom: 'calc(1rem + env(safe-area-inset-bottom))' } : {}}>
                    <button type="button" onClick={handleOpenCharacterGen} className={`flex items-center justify-center gap-2 font-semibold btn-pressable bg-teal-600 text-white hover:bg-teal-500 ${isMobile ? 'w-full py-3 rounded-md text-base order-1' : 'px-4 py-2 text-sm rounded-md transition'}`}><Icons.MoonIcon className={isMobile ? "h-5 w-5" : "h-4 w-4"} /><span>AIアシスタント</span></button>
                    <div className={`flex gap-3 ${isMobile ? 'flex-col w-full order-2' : ''}`}>
                        <button type="button" onClick={handleCloseRequest} className={buttonClass('bg-gray-600 hover:bg-gray-500')}><Icons.XIcon className="h-4 w-4" />キャンセル</button>
                        <button type="submit" form="character-form" data-testid="modal-save-button" className={buttonClass('bg-indigo-600 hover:bg-indigo-500 font-bold')}><Icons.CheckIcon className="h-4 w-4" />保存</button>
                    </div>
                </div>
            </div>
        </div>
    );
};

import React, { useEffect, useRef, useState } from 'react';
import { Tutorial } from './components/Tutorial';
import { ResizableHandle } from './components/ResizableHandle';
import { Header } from './components/Header';
import { LeftPanel } from './components/LeftPanel';
import { ActivityBar } from './components/ActivityBar';
import { NovelEditor } from './components/NovelEditor';
import { RightPanel } from './components/RightPanel';
import { ModalManager } from './components/ModalManager';
import { CommandPalette } from './components/CommandPalette';
import { FloatingWindow } from './components/FloatingWindow';
import { useStore } from './store/index';
import { useKeybindings } from './hooks/useKeybindings';
import { useSidebarResize } from './hooks/useSidebarResize';
import { ProjectSelectionScreen } from './components/ProjectSelectionScreen';
import { Toast } from './components/Toast';
import { TutorialModeSelectionModal } from './components/TutorialModeSelectionModal';
import AppMobile from './App.mobile';

export default function App() {
    // --- Zustand Store Selectors ---
    const activeProjectId = useStore(state => state.activeProjectId);
    const allProjectsData = useStore(state => state.allProjectsData);
    const isLeftSidebarOpen = useStore(state => state.isLeftSidebarOpen);
    const isRightSidebarOpen = useStore(state => state.isRightSidebarOpen);
    const leftSidebarWidth = useStore(state => state.leftSidebarWidth);
    const rightSidebarWidth = useStore(state => state.rightSidebarWidth);
    const hasCompletedGlobalTutorial = useStore(state => state.hasCompletedGlobalTutorial);
    const floatingWindows = useStore(state => state.floatingWindows);
    const activeModal = useStore(state => state.activeModal);
    const editingChunkId = useStore(state => state.editingChunkId);
    const generationMode = useStore(state => state.generationMode);
    const novelContent = useStore(state => activeProjectId ? state.allProjectsData[activeProjectId]?.novelContent : []);

    const createProject = useStore(state => state.createProject);
    const deleteProject = useStore(state => state.deleteProject);
    const importProject = useStore(state => state.importProject);
    const setActiveProjectId = useStore(state => state.setActiveProjectId);
    const setLeftSidebarWidth = useStore(state => state.setLeftSidebarWidth);
    const setRightSidebarWidth = useStore(state => state.setRightSidebarWidth);
    const openModal = useStore(state => state.openModal);
    const setIsLeftSidebarOpen = useStore(state => state.setIsLeftSidebarOpen);
    const setIsRightSidebarOpen = useStore(state => state.setIsRightSidebarOpen);
    const setGenerationMode = useStore(state => state.setGenerationMode);
    const undo = useStore(state => state.undo);
    const redo = useStore(state => state.redo);
    const setEditingChunkId = useStore(state => state.setEditingChunkId);

    const displayMenuButtonRef = useRef(null);
    const userInputRef = useRef<HTMLTextAreaElement>(null);
    const { isResizing, handleResizeStart } = useSidebarResize(
        leftSidebarWidth,
        setLeftSidebarWidth,
        rightSidebarWidth,
        setRightSidebarWidth,
    );

    const activeProjectData = activeProjectId ? allProjectsData[activeProjectId] : null;
    const displaySettings = activeProjectData?.displaySettings;
    const isSwapped = displaySettings?.swapSidebars ?? false;

    // Mobile Detection with Threshold Stability
    const [isMobile, setIsMobile] = useState(false);
    useEffect(() => {
        const checkMobile = () => {
            const width = window.innerWidth;
            // 768px付近でのチャタリング（リサイズによる頻繁な切り替わり）を防ぐため判定を工夫
            setIsMobile(prev => {
                if (prev) return width < 800; // 一度モバイルになったら800pxまでモバイル維持
                return width < 768; // デスクトップからは768px未満で切り替え
            });
        };
        checkMobile();
        window.addEventListener('resize', checkMobile);
        return () => window.removeEventListener('resize', checkMobile);
    }, []);

    useKeybindings({
        isAnyModalOpen: activeModal !== null,
        editingChunkId: editingChunkId,
        openModal: openModal,
        setIsLeftSidebarOpen: setIsLeftSidebarOpen,
        setIsRightSidebarOpen: setIsRightSidebarOpen,
        userInputRef: userInputRef,
        generationMode: generationMode,
        setGenerationMode: setGenerationMode,
        undo: undo,
        redo: redo,
        novelContent: novelContent,
        setEditingChunkId: setEditingChunkId
    });

    useEffect(() => {
        if (activeProjectData && !hasCompletedGlobalTutorial && !activeProjectData.isSimpleMode) {
            const timer = setTimeout(() => openModal('tutorialModeSelection'), 500);
            return () => clearTimeout(timer);
        }
    }, [activeProjectData, hasCompletedGlobalTutorial, openModal]);

    // Handle knowledge link clicks globally
    useEffect(() => {
        const handleClick = (event: MouseEvent) => {
            const target = (event.target as HTMLElement).closest('.knowledge-link');
            if (target) {
                event.preventDefault();
                const knowledgeId = target.getAttribute('data-knowledge-id');
                if (knowledgeId) {
                    const knowledgeBase = useStore.getState().allProjectsData[useStore.getState().activeProjectId || '']?.knowledgeBase || [];
                    const item = knowledgeBase.find(k => k.id === knowledgeId);
                    if (item) openModal('knowledge', item);
                }
            }
        };
        const rootElement = document.getElementById('root');
        if (rootElement) rootElement.addEventListener('click', handleClick);
        return () => { if (rootElement) rootElement.addEventListener('click', handleClick); };
    }, [openModal]);


    const handleExportProject = (projectId: string) => {
        const projectData = allProjectsData[projectId];
        if (!projectData) return;
        const dataStr = JSON.stringify(projectData, null, 2);
        const link = document.createElement('a');
        link.href = URL.createObjectURL(new Blob([dataStr], { type: 'application/json' }));
        link.download = `${projectData.name}.json`;
        link.click();
        URL.revokeObjectURL(link.href);
    };
     const handleExportTxt = () => {
        if (!activeProjectData) return;
        const textContent = activeProjectData.novelContent.map(chunk => chunk.text).join('\n\n');
        const link = document.createElement('a');
        link.href = URL.createObjectURL(new Blob([textContent], { type: 'text/plain;charset=utf-8' }));
        link.download = `${activeProjectData.name}.txt`;
        link.click();
        URL.revokeObjectURL(link.href);
    };

    if (!activeProjectId || !activeProjectData) {
        return <ProjectSelectionScreen projects={Object.values(allProjectsData)} onCreateProject={createProject} onDeleteProject={deleteProject} onImportProject={importProject} onSelectProject={setActiveProjectId} />;
    }

    // Mobile View
    if (isMobile) {
        return <AppMobile />;
    }

    // Desktop View
    const spacer = !activeProjectData?.isSimpleMode ? <div className="w-14 flex-shrink-0" /> : null;
    const activityBar = !activeProjectData?.isSimpleMode ? <ActivityBar /> : null;

    const leftPanelArea = isLeftSidebarOpen && (
        <>
            <LeftPanel onExportProject={() => handleExportProject(activeProjectId)} onExportTxt={handleExportTxt} />
            <ResizableHandle onMouseDown={(e) => handleResizeStart('left', e)} />
        </>
    );

    const rightPanelArea = isRightSidebarOpen && (
        <>
            <ResizableHandle onMouseDown={(e) => handleResizeStart('right', e)} />
            <RightPanel userInputRef={userInputRef} />
        </>
    );

    const mainContent = (
        <div className="flex-1 flex flex-col bg-gray-900 min-w-0 min-h-0">
            <Header displayMenuButtonRef={displayMenuButtonRef} />
            <NovelEditor />
        </div>
    );

    return (
        <div className="flex h-screen bg-gray-900 text-gray-200 overflow-hidden relative">
            <Toast />
            <Tutorial />
            <TutorialModeSelectionModal />
            <ModalManager displayMenuButtonRef={displayMenuButtonRef} isMobile={isMobile} />
            <CommandPalette />

            {floatingWindows.map(window => (
                <FloatingWindow key={window.id} {...window} />
            ))}

            {isSwapped ? (
                <>
                    {/* 入れ替え時: [ 右パネル | メイン | 左パネル | バー(fixed) ] */}
                    {rightPanelArea}
                    {mainContent}
                    <div className="flex h-full flex-shrink-0">
                        {leftPanelArea}
                        {spacer}
                        {activityBar}
                    </div>
                </>
            ) : (
                <>
                    {/* 通常時: [ バー(fixed) | 左パネル | メイン | 右パネル ] */}
                    <div className="flex h-full flex-shrink-0">
                        {activityBar}
                        {spacer}
                        {leftPanelArea}
                    </div>
                    {mainContent}
                    {rightPanelArea}
                </>
            )}
        </div>
    );
}

import React, { useRef, useEffect, useState } from 'react';
import { NovelEditor } from './components/NovelEditor';
import { Header } from './components/Header';
import { Toast } from './components/Toast';
import { ModalManager } from './components/ModalManager';
import { CommandPalette } from './components/CommandPalette';
import { Tutorial } from './components/Tutorial';
import { TutorialModeSelectionModal } from './components/TutorialModeSelectionModal';
import { useStore } from './store/index';
import { LeftPanel } from './components/LeftPanel';
import { RightPanel } from './components/RightPanel';

const AppMobile: React.FC = () => {
    // Headerコンポーネントが必要とするrefを作成
    const displayMenuButtonRef = useRef<HTMLButtonElement>(null);
    const userInputRef = useRef<HTMLTextAreaElement>(null);

    const activeProjectId = useStore(state => state.activeProjectId);
    const allProjectsData = useStore(state => state.allProjectsData);
    const hasCompletedGlobalTutorial = useStore(state => state.hasCompletedGlobalTutorial);
    const openModal = useStore(state => state.openModal);

    const isLeftSidebarOpen = useStore(state => state.isLeftSidebarOpen);
    const isRightSidebarOpen = useStore(state => state.isRightSidebarOpen);
    const setIsLeftSidebarOpen = useStore(state => state.setIsLeftSidebarOpen);
    const setIsRightSidebarOpen = useStore(state => state.setIsRightSidebarOpen);

    const activeProjectData = activeProjectId ? allProjectsData[activeProjectId] : null;

    const [isInitialized, setIsInitialized] = useState(false);
    const [viewportHeight, setViewportHeight] = useState('100dvh');

    // スワイプ操作用のRef
    const touchStartRef = useRef<{ x: number; y: number } | null>(null);

    useEffect(() => {
        // スマホ版起動時は左右のカラムを閉じる
        setIsLeftSidebarOpen(false);
        setIsRightSidebarOpen(false);

        // 初期化完了フラグを立てる
        const timer = setTimeout(() => {
            setIsInitialized(true);
        }, 100);

        return () => clearTimeout(timer);
    }, [setIsLeftSidebarOpen, setIsRightSidebarOpen]);

    // Visual Viewport APIによるキーボード表示時の高さ調整
    useEffect(() => {
        const handleResize = () => {
            if (window.visualViewport) {
                setViewportHeight(`${window.visualViewport.height}px`);
                // キーボード表示時にレイアウトが崩れないようトップにスクロール固定
                window.scrollTo(0, 0);
            } else {
                setViewportHeight(`${window.innerHeight}px`);
            }
        };

        if (window.visualViewport) {
            window.visualViewport.addEventListener('resize', handleResize);
            handleResize(); // 初期値設定
        } else {
            window.addEventListener('resize', handleResize);
        }

        return () => {
            if (window.visualViewport) {
                window.visualViewport.removeEventListener('resize', handleResize);
            } else {
                window.removeEventListener('resize', handleResize);
            }
        };
    }, []);

    useEffect(() => {
        if (isInitialized && activeProjectData && !hasCompletedGlobalTutorial) {
            // スマホ版でも初回チュートリアル選択を表示
            const timer = setTimeout(() => openModal('tutorialModeSelection'), 500);
            return () => clearTimeout(timer);
        }
    }, [isInitialized, activeProjectData, hasCompletedGlobalTutorial, openModal]);

    const handleTouchStart = (e: React.TouchEvent) => {
        touchStartRef.current = { x: e.touches[0].clientX, y: e.touches[0].clientY };
    };

    const handleTouchEnd = (e: React.TouchEvent) => {
        if (!touchStartRef.current) return;

        const touchEnd = { x: e.changedTouches[0].clientX, y: e.changedTouches[0].clientY };
        const diffX = touchEnd.x - touchStartRef.current.x;
        const diffY = touchEnd.y - touchStartRef.current.y;
        const startX = touchStartRef.current.x;

        touchStartRef.current = null;

        // 誤爆防止ロジックの強化
        // 1. 横移動が縦移動の2倍以上であること (意図的な横スワイプのみを検出)
        if (Math.abs(diffX) < Math.abs(diffY) * 2) return;

        // しきい値設定
        const minSwipeDistance = 50; // スワイプとみなす最小距離
        const edgeThreshold = 50; // エッジスワイプとみなす画面端からの距離
        const maxVerticalDeviation = 50; // 許容する縦方向のズレ (100から50へ厳格化)

        if (Math.abs(diffX) < minSwipeDistance) return;
        if (Math.abs(diffY) > maxVerticalDeviation) return;

        const screenWidth = window.innerWidth;

        if (diffX > 0) {
            // 右スワイプ ( -> )
            if (isRightSidebarOpen) {
                // 右パネルが開いていれば閉じる
                setIsRightSidebarOpen(false);
            } else if (!isLeftSidebarOpen && startX < edgeThreshold) {
                // 左パネルが閉じていて、左端からのスワイプなら開く
                setIsLeftSidebarOpen(true);
            }
        } else {
            // 左スワイプ ( <- )
            if (isLeftSidebarOpen) {
                // 左パネルが開いていれば閉じる
                setIsLeftSidebarOpen(false);
            } else if (!isRightSidebarOpen && startX > screenWidth - edgeThreshold) {
                // 右パネルが閉じていて、右端からのスワイプなら開く
                setIsRightSidebarOpen(true);
            }
        }
    };

    const handleExportProject = (projectId: string) => {
        const projectData = allProjectsData[projectId];
        if (!projectData) return;
        const dataStr = JSON.stringify(projectData, null, 2);
        const link = document.createElement('a');
        link.href = URL.createObjectURL(new Blob([dataStr], { type: 'application/json' }));
        link.download = `${projectData.name}.json`;
        link.click();
        URL.revokeObjectURL(link.href);
    };
     const handleExportTxt = () => {
        if (!activeProjectData) return;
        const textContent = activeProjectData.novelContent.map(chunk => chunk.text).join('\n\n');
        const link = document.createElement('a');
        link.href = URL.createObjectURL(new Blob([textContent], { type: 'text/plain;charset=utf-8' }));
        link.download = `${activeProjectData.name}.txt`;
        link.click();
        URL.revokeObjectURL(link.href);
    };

    // データ読み込み中、または初期化処理中はローディングを表示
    if (!activeProjectData || !isInitialized) {
        return (
            <div className="flex flex-col items-center justify-center h-[100dvh] bg-gray-900 text-gray-400 gap-4">
                <div className="w-8 h-8 border-4 border-indigo-500 border-t-transparent rounded-full animate-spin"></div>
                <p>物語を読み込んでいます...</p>
            </div>
        );
    }

    return (
        <div 
            className="flex flex-col w-full bg-gray-900 text-gray-200 overflow-hidden relative"
            style={{ height: viewportHeight }} // 動的な高さを適用
            onTouchStart={handleTouchStart}
            onTouchEnd={handleTouchEnd}
        >
            {/* アプリケーション機能に必要なオーバーレイコンポーネント */}
            <Toast />
            <Tutorial isMobile={true} />
            <TutorialModeSelectionModal />
            <ModalManager displayMenuButtonRef={displayMenuButtonRef} isMobile={true} />
            <CommandPalette />

            {/* ヘッダーエリア */}
            <div className="w-full border-b border-gray-700 bg-gray-800 flex-shrink-0 z-30">
                <Header displayMenuButtonRef={displayMenuButtonRef} isMobile={true} />
            </div>

            {/* 1カラムエディタエリア */}
            <div className="flex-1 overflow-hidden flex flex-col relative z-0 min-h-0">
                <NovelEditor />
            </div>

            {/* オーバーレイパネル: 左 (設定・アウトライン) */}
            {isLeftSidebarOpen && (
                <div 
                    className="fixed inset-0 z-40 bg-gray-900 flex flex-col animate-slide-in-left shadow-2xl"
                    style={{ height: viewportHeight }} // 動的な高さを適用
                >
                    <LeftPanel 
                        onExportProject={() => activeProjectId && handleExportProject(activeProjectId)} 
                        onExportTxt={handleExportTxt} 
                        isMobile={true}
                    />
                </div>
            )}

            {/* オーバーレイパネル: 右 (AIアシスタント) */}
            {isRightSidebarOpen && (
                <div 
                    className="fixed inset-0 z-40 bg-gray-900 flex flex-col animate-slide-in-right shadow-2xl"
                    style={{ height: viewportHeight }} // 動的な高さを適用
                >
                    <RightPanel 
                        userInputRef={userInputRef}
                        isMobile={true}
                    />
                </div>
            )}
        </div>
    );
};

export default AppMobile;

import React, { useState, useEffect, useRef, useMemo } from 'react';
import * as Icons from '../icons';
import { useStore } from '../store/index';
import { EditableParagraph } from './EditableParagraph';
import { TextSelectionToolbar } from './TextSelectionToolbar';
import { NovelChunk } from '../types';
import { FONT_MAP, defaultDisplaySettings } from '../constants';
import { Tooltip } from './Tooltip';

export const NovelEditor: React.FC = () => {
    const activeProjectId = useStore(state => state.activeProjectId);
    const activeProjectData = useStore(state => state.allProjectsData[activeProjectId]);

    if (!activeProjectData) return null;

    const { novelContent, settings, knowledgeBase, displaySettings: projectDisplaySettings } = activeProjectData;
    const displaySettings = projectDisplaySettings || defaultDisplaySettings;

    const highlightedChunkId = useStore(state => state.highlightedChunkId);
    const editingChunkId = useStore(state => state.editingChunkId);
    const newChunkText = useStore(state => state.newChunkText);
    const isNewChunkInputOpen = useStore(state => state.isNewChunkInputOpen);

    const setEditingChunkId = useStore(state => state.setEditingChunkId);
    const handleNovelTextChange = useStore(state => state.handleNovelTextChange);
    const handleToggleChunkPin = useStore(state => state.handleToggleChunkPin);
    const setNewChunkText = useStore(state => state.setNewChunkText);
    const setIsNewChunkInputOpen = useStore(state => state.setIsNewChunkInputOpen);
    const handleAddNewChunk = useStore(state => state.handleAddNewChunk);
    const setUserInput = useStore(state => state.setUserInput);
    const setIsRightSidebarOpen = useStore(state => state.setIsRightSidebarOpen);

    const novelContentRef = useRef<HTMLDivElement>(null);
    const newChunkTextareaRef = useRef<HTMLTextAreaElement>(null);
    const isMac = useMemo(() => navigator.platform.toUpperCase().indexOf('MAC') >= 0, []);
    const modifierKeyText = isMac ? '⌘Cmd' : 'Ctrl';

    const [selectionToolbar, setSelectionToolbar] = useState<{ top: number; left: number } | null>(null);
    const selectionRef = useRef({ text: '', range: null });

    useEffect(() => {
        if (newChunkTextareaRef.current) {
            newChunkTextareaRef.current.style.height = 'auto';
            const scrollHeight = newChunkTextareaRef.current.scrollHeight;
            newChunkTextareaRef.current.style.height = `${scrollHeight}px`;
        }
    }, [newChunkText]);

    useEffect(() => {
        if (editingChunkId) {
            document.getElementById(`chunk-${editingChunkId}`)?.scrollIntoView({ behavior: 'smooth', block: 'center' });
        }
    }, [editingChunkId]);

    useEffect(() => {
        const handleSelectionChange = () => {
            const selection = window.getSelection();
            if (selection && selection.rangeCount > 0) {
                const range = selection.getRangeAt(0);
                const text = selection.toString().trim();

                if (text && novelContentRef.current?.contains(range.commonAncestorContainer)) {
                    selectionRef.current = { text, range };
                    const rect = range.getBoundingClientRect();
                    const editorRect = novelContentRef.current.getBoundingClientRect();
                    setSelectionToolbar({
                        top: rect.top - editorRect.top - 40,
                        left: rect.left - editorRect.left + rect.width / 2,
                    });
                } else {
                    setSelectionToolbar(null);
                    selectionRef.current = { text: '', range: null };
                }
            }
        };

        const editorElement = novelContentRef.current;
        if (editorElement) {
            document.addEventListener('selectionchange', handleSelectionChange);
            editorElement.addEventListener('mousedown', () => setSelectionToolbar(null));
        }
        return () => {
            document.removeEventListener('selectionchange', handleSelectionChange);
            if (editorElement) {
                editorElement.removeEventListener('mousedown', () => setSelectionToolbar(null));
            }
        };
    }, []);

    const handleToolbarAction = (actionType: 'proofread' | 'summarize' | 'poetic' | 'dialogue') => {
        const selectedText = selectionRef.current.text;
        if (!selectedText) return;

        let prompt = '';
        switch (actionType) {
            case 'proofread':
                prompt = `以下の文章の誤字脱字や文法的な誤りを修正してください。:\n\n「${selectedText}」`;
                break;
            case 'summarize':
                prompt = `以下の文章を簡潔に要約してください。:\n\n「${selectedText}」`;
                break;
            case 'poetic':
                prompt = `以下の文章を、より詩的で感情豊かな表現に書き換えてください。:\n\n「${selectedText}」`;
                break;
            case 'dialogue':
                prompt = `以下の地の文を、キャラクターの会話文に変換してください。:\n\n「${selectedText}」`;
                break;
        }

        setUserInput(prompt);
        setIsRightSidebarOpen(true);
        setSelectionToolbar(null);
        window.getSelection()?.removeAllRanges();
    };

    const chapters = useMemo(() => {
        if (!novelContent) return [];
        const result: { id: string; title: string; memo?: string; chunks: NovelChunk[] }[] = [];
        let currentChapterChunks: NovelChunk[] = [];

        const extractTitleFromChunkText = (chunkText: string) => {
            if (!chunkText.startsWith('# ')) return '';
            const firstLine = chunkText.split('\n')[0];
            return firstLine.substring(2).trim();
        };

        novelContent.forEach((chunk) => {
            const isTitle = chunk.text.startsWith('# ');
            if (isTitle) {
                if (currentChapterChunks.length > 0) {
                    const firstChunkOfPreviousBlock = currentChapterChunks[0];
                    const isPreviousBlockTitled = firstChunkOfPreviousBlock.text.startsWith('# ');

                    if (isPreviousBlockTitled) {
                        result.push({ id: firstChunkOfPreviousBlock.id, title: extractTitleFromChunkText(firstChunkOfPreviousBlock.text) || '無題の章', memo: firstChunkOfPreviousBlock.memo, chunks: currentChapterChunks });
                    } else {
                        result.push({ id: firstChunkOfPreviousBlock.id, title: '章に属さない文章', chunks: currentChapterChunks });
                    }
                }
                currentChapterChunks = [chunk];
            } else {
                currentChapterChunks.push(chunk);
            }
        });

        if (currentChapterChunks.length > 0) {
            const firstChunk = currentChapterChunks[0];
            const isTitled = firstChunk.text.startsWith('# ');
            result.push({ id: firstChunk.id, title: isTitled ? (extractTitleFromChunkText(firstChunk.text) || '無題の章') : '章に属さない文章', memo: isTitled ? firstChunk.memo : undefined, chunks: currentChapterChunks });
        }

        return result;
    }, [novelContent]);

    const handleNewChunkKeyDown = (e: React.KeyboardEvent<HTMLTextAreaElement>) => {
        if (e.key === 'Enter' && (e.ctrlKey || e.metaKey)) {
            e.preventDefault();
            if (newChunkText.trim()) {
                handleAddNewChunk();
            }
        }
    };

    const themes = { light: { bg: 'bg-white', text: 'text-gray-800', prose: '' }, sepia: { bg: 'bg-[#fbf0d9]', text: 'text-[#5b4636]', prose: 'prose-sepia' }, dark: { bg: 'bg-gray-800', text: 'text-gray-200', prose: 'prose-invert' } };
    const contentStyles = { fontFamily: FONT_MAP[displaySettings.fontFamily] || FONT_MAP['sans'], fontSize: `${displaySettings.fontSize}px`, lineHeight: 1.8 };
    const proseClasses = ['prose', 'prose-lg', 'max-w-full', (themes[displaySettings.theme] || themes.light).prose].filter(Boolean).join(' ');
    const themeClass = themes[displaySettings?.theme] || themes.light;
    const newChunkInputTextColor = {
        light: 'black',
        sepia: '#555555',
        dark: '#d1d5db',
    }[displaySettings.theme] || 'black';

    return (
        <div className="flex-1 flex flex-col min-h-0 relative bg-gray-900">
            <div
                id="novel-editor-content"
                tabIndex={-1}
                ref={novelContentRef}
                className={`flex-1 p-6 pb-32 overflow-y-auto min-h-0 transition-colors duration-300 ${themeClass.bg} ${themeClass.text} focus:outline-none focus:ring-2 focus:ring-indigo-500 relative`}
                data-tutorial-id="tutorial-center-panel"
            >
                {selectionToolbar && <TextSelectionToolbar position={selectionToolbar} onAction={handleToolbarAction} />}
                <div className={proseClasses}>
                    {chapters.map(chapter => (
                        <div key={chapter.id} id={`chapter-scroll-${chapter.id}`} className="chapter-group">
                            {chapter.chunks.map(chunk => (
                                <EditableParagraph key={chunk.id} chunk={chunk} characters={settings.filter(s => s.type === 'character')} knowledgeBase={knowledgeBase} onTextChange={handleNovelTextChange} onTogglePin={handleToggleChunkPin} isHighlighted={chunk.id === highlightedChunkId} isEditing={chunk.id === editingChunkId} onStartEdit={() => setEditingChunkId(chunk.id)} onEndEdit={() => setEditingChunkId(null)} scrollContainerRef={novelContentRef} />
                            ))}
                        </div>
                    ))}
                    {novelContent.length === 0 && <p className="text-gray-500">ここに物語が生成されます...</p>}
                </div>
            </div>
            <div 
                className={`border-t border-gray-700/50 flex-shrink-0 z-10 relative shadow-[0_-4px_12px_rgba(0,0,0,0.15)] ${themeClass.bg}`}
                style={{ paddingBottom: 'env(safe-area-inset-bottom)' }}
            >
                <Tooltip helpId="direct_input_open">
                    <div className="group flex justify-between items-center p-2 cursor-pointer hover:bg-gray-700" onClick={() => setIsNewChunkInputOpen(p => !p)} aria-expanded={isNewChunkInputOpen} aria-controls="new-chunk-panel">
                        <h3 className="text-sm font-semibold text-gray-400 group-hover:text-white transition-colors">本文を直接入力</h3>
                        <button className="p-1 text-gray-400 group-hover:text-white transition-colors btn-pressable" aria-label={isNewChunkInputOpen ? '入力を閉じる' : '入力を開く'}>{isNewChunkInputOpen ? <Icons.ChevronDownIcon className="h-5 w-5" /> : <Icons.ChevronUpIcon className="h-5 w-5" />}</button>
                    </div>
                </Tooltip>
                <div id="new-chunk-panel" className={`transition-all duration-300 ease-in-out overflow-hidden ${isNewChunkInputOpen ? 'max-h-96' : 'max-h-0'}`}>
                    <div className="p-4 pt-0">
                        <textarea
                            ref={newChunkTextareaRef}
                            value={newChunkText}
                            onChange={(e) => setNewChunkText(e.target.value)}
                            onKeyDown={handleNewChunkKeyDown}
                            placeholder="ここに新しい段落を直接入力できます..."
                            className={`w-full border rounded-md p-3 focus:ring-indigo-500 focus:border-indigo-500 resize-none transition-colors duration-300`}
                            style={{ ...contentStyles, color: newChunkInputTextColor, backgroundColor: 'rgba(128, 128, 128, 0.1)' }}
                            rows={3}
                        />
                        <div className="flex justify-end mt-2"><button onClick={handleAddNewChunk} disabled={!newChunkText.trim()} className="px-4 py-2 text-sm rounded-md disabled:bg-gray-500 btn-pressable btn-invert-indigo">本文に追加 <span className="text-xs opacity-80 ml-1">({modifierKeyText}+Enterで追加)</span></button></div>
                    </div>
                </div>
            </div>
        </div>
    );
};

