export const CharacterChartModal = ({ isOpen, onClose, characters, relations, nodePositions, onSave, onHelpClick, isMobile = false }) => {
    type LocalNode = SettingItem & NodePosition;
    const [localNodes, setLocalNodes] = useState<LocalNode[]>([]);
    const [localRelations, setLocalRelations] = useState(relations);
    const [activeDrag, setActiveDrag] = useState(null);
    const [isEditingRelation, setIsEditingRelation] = useState(null);
    const [mode, setMode] = useState<'navigate' | 'add_relation' | 'delete_relation'>('navigate');
    const [firstSelectionForAdd, setFirstSelectionForAdd] = useState<string | null>(null);
    const svgRef = useRef(null);
    const [isConfirmCloseOpen, setIsConfirmCloseOpen] = useState(false);
    const [initialStateString, setInitialStateString] = useState('');
    const closeButtonRef = useRef(null);
    const isOpenRef = useRef(isOpen);

    const hasCompletedGlobalChartTutorial = useStore(state => state.hasCompletedGlobalChartTutorial);
    const startChartTutorial = useStore(state => state.startChartTutorial);

    useEffect(() => {
        if (isOpen && !hasCompletedGlobalChartTutorial && !isMobile) {
            const timer = setTimeout(() => {
                startChartTutorial();
            }, 300);
            return () => clearTimeout(timer);
        }
    }, [isOpen, hasCompletedGlobalChartTutorial, startChartTutorial, isMobile]);

    // モーダルが開いた瞬間だけ初期データをセットするように修正（Propsの変更による自動リセットを防止）
    useEffect(() => {
        if (isOpen && !isOpenRef.current) {
            setLocalRelations(relations);
            setIsEditingRelation(null);
            setMode('navigate');
            setFirstSelectionForAdd(null);

            const chartWidth = 800;
            const chartHeight = 600;

            const updatedNodes = characters.map((char, index) => {
                const existingPos = nodePositions.find(p => p.characterId === char.id);
                if (existingPos) {
                    return { ...char, ...existingPos };
                }
                const angle = (index / characters.length) * 2 * Math.PI;
                const radius = Math.min(chartWidth, chartHeight) / 3;
                return {
                    ...char,
                    characterId: char.id,
                    x: chartWidth / 2 + radius * Math.cos(angle),
                    y: chartHeight / 2 + radius * Math.sin(angle),
                };
            });
            setLocalNodes(updatedNodes as LocalNode[]);
            const initialState = {
                relations,
                nodePositions: updatedNodes.map(n => ({ characterId: n.id, x: n.x, y: n.y }))
            };
            setInitialStateString(JSON.stringify(initialState));
        }
        isOpenRef.current = isOpen;
    }, [isOpen, characters, relations, nodePositions]);

    useEffect(() => {
        setFirstSelectionForAdd(null);
    }, [mode]);

    const isDirty = useMemo(() => {
        if (!initialStateString) return false;
        const currentState = {
            relations: localRelations,
            nodePositions: localNodes.map(n => ({ characterId: n.id, x: n.x, y: n.y })),
        };
        return JSON.stringify(currentState) !== initialStateString;
    }, [localNodes, localRelations, initialStateString]);

    const relationsWithCurveData = useMemo(() => {
        const pairs = new Map<string, Relation[]>();
        localRelations.forEach(rel => {
            const key = [rel.source, rel.target].sort().join('--');
            if (!pairs.has(key)) {
                pairs.set(key, []);
            }
            pairs.get(key)!.push(rel);
        });

        return localRelations.map(rel => {
            const key = [rel.source, rel.target].sort().join('--');
            const pair = pairs.get(key)!;
            const isBidirectional = pair.length > 1 && pair.some(p => p.source === rel.target && p.target === rel.source);

            let curve = 0;
            if (isBidirectional) {
                curve = 30;
            }

            return { ...rel, curve };
        });
    }, [localRelations]);

    const handleSave = () => {
        const newPositions = localNodes.map(({ id, x, y }) => ({ characterId: id, x, y }));
        onSave(localRelations, newPositions);
        onClose();
    };

    const handleCloseRequest = () => {
        if (isDirty && !isMobile) {
            setIsConfirmCloseOpen(true);
        } else {
            onClose();
        }
    };

    const handleSaveAndClose = () => {
        handleSave();
        setIsConfirmCloseOpen(false);
    };

    const getSVGPoint = (e) => {
        const svg = svgRef.current;
        if (!svg) return { x: 0, y: 0 };
        const pt = svg.createSVGPoint();
        pt.x = e.clientX;
        pt.y = e.clientY;
        return pt.matrixTransform(svg.getScreenCTM().inverse());
    };

    const handleMouseDown = (e, nodeId) => {
        e.preventDefault();
        if (mode !== 'navigate') return;
        const point = getSVGPoint(e);
        const node = localNodes.find(n => n.id === nodeId);
        setActiveDrag({
            nodeId,
            offsetX: point.x - node.x,
            offsetY: point.y - node.y,
        });
    };

    const handleMouseMove = (e) => {
        if (!activeDrag) return;
        e.preventDefault();
        const point = getSVGPoint(e);
        setLocalNodes(prevNodes => prevNodes.map(node =>
            node.id === activeDrag.nodeId
                ? { ...node, x: point.x - activeDrag.offsetX, y: point.y - activeDrag.offsetY }
                : node
        ));
    };

    const handleMouseUp = (e) => {
        setActiveDrag(null);
    };

    const handleNodeClick = (e, node) => {
        e.stopPropagation(); 

        if (mode === 'add_relation') {
             if (!firstSelectionForAdd) {
                setFirstSelectionForAdd(node.id);
            } else {
                const existingRelation = localRelations.find(
                    r => r.source === firstSelectionForAdd && r.target === node.id
                );

                if (existingRelation) {
                    setIsEditingRelation(existingRelation);
                } else {
                    const newRelation: Relation = {
                        id: uuidv4(),
                        source: firstSelectionForAdd,
                        target: node.id,
                        label: "関係",
                        color: "#6b7280",
                        callName: ""
                    };
                    setIsEditingRelation(newRelation);
                }

                setMode('navigate');
                setFirstSelectionForAdd(null);
            }
        } else if (mode === 'delete_relation') {
            if (!firstSelectionForAdd) {
                setFirstSelectionForAdd(node.id);
            } else {
                const sourceId = firstSelectionForAdd;
                const targetId = node.id;

                if (sourceId !== targetId) {
                    const relationsToDelete = localRelations.filter(
                        r => (r.source === sourceId && r.target === targetId) ||
                             (r.source === targetId && r.target === sourceId)
                    );

                    if (relationsToDelete.length > 0) {
                        const sourceCharName = localNodes.find(n => n.id === sourceId)?.name || '不明なキャラクター';
                        const targetCharName = localNodes.find(n => n.id === targetId)?.name || '不明なキャラクター';
                        if (window.confirm(`${sourceCharName} と ${targetCharName} の間にあるすべての関係（${relationsToDelete.length}件）を削除しますか？`)) {
                            const idsToDelete = new Set(relationsToDelete.map(r => r.id));
                            setLocalRelations(prev => prev.filter(r => !idsToDelete.has(r.id)));
                        }
                    }
                }
                setFirstSelectionForAdd(null);
                // 連続削除ができるように、あえてnavigateに戻さない選択肢もあり
            }
        }
    };

    const handleDeleteRelation = (relationId: string) => {
        setLocalRelations(prev => prev.filter(r => r.id !== relationId));
    };

    const handleRelationSave = (savedRelation) => {
        setLocalRelations(prev => {
            const exists = prev.some(r => r.id === savedRelation.id);
            if (exists) {
                return prev.map(r => r.id === savedRelation.id ? savedRelation : r);
            }
            return [...prev, savedRelation];
        });
        setIsEditingRelation(null);
    };

    const handleBackgroundClick = () => {
        if (mode === 'add_relation' && firstSelectionForAdd) {
            return;
        }
        setMode('navigate');
        setFirstSelectionForAdd(null);
    };

    if (!isOpen) return null;

    const nodesById = localNodes.reduce((acc, node) => ({ ...acc, [node.id]: node }), {});

    return createPortal(
        <div className="fixed inset-0 bg-black/80 backdrop-blur-sm flex justify-center items-center z-[70] p-4">
            {!isMobile && <ChartTutorial />}
            <div className="bg-gray-800 rounded-lg shadow-xl w-full max-w-5xl h-[90vh] flex flex-col border border-gray-700 relative">
                <UnsavedChangesPopover
                    isOpen={isConfirmCloseOpen}
                    targetRef={closeButtonRef}
                    onCancel={() => setIsConfirmCloseOpen(false)}
                    onCloseWithoutSaving={() => { setIsConfirmCloseOpen(false); onClose(); }}
                    onSaveAndClose={handleSaveAndClose}
                />
                <div className="flex justify-between items-center p-4 border-b border-gray-700 flex-shrink-0">
                    <div className="flex items-center gap-2">
                        <h2 className="text-xl font-bold text-violet-400 flex items-center"><Icons.UserCogIcon />キャラクター相関図</h2>
                    </div>
                     <div className="flex items-center gap-2">
                        <div className="flex items-center p-1 bg-gray-900 rounded-lg">
                            <button id="tutorial-chart-navigate-btn" onClick={() => setMode('navigate')} className={`px-3 py-1 text-xs rounded ${mode === 'navigate' ? 'bg-indigo-600' : ''} text-white btn-pressable`}>移動</button>
                            <button id="tutorial-chart-add-btn" onClick={() => setMode('add_relation')} className={`px-3 py-1 text-xs rounded ${mode === 'add_relation' ? 'bg-indigo-600' : ''} text-white btn-pressable`}>関係を追加</button>
                            <button id="tutorial-chart-delete-btn" onClick={() => setMode('delete_relation')} className={`px-3 py-1 text-xs rounded ${mode === 'delete_relation' ? 'bg-indigo-600' : ''} text-white btn-pressable`}>関係を削除</button>
                        </div>
                        <button onClick={() => onHelpClick('characterChart')} className="p-1.5 rounded-full text-gray-400 hover:text-white hover:bg-gray-700 transition btn-pressable" title="ヘルプ">
                            <Icons.HelpCircleIcon className="h-5 w-5" />
                        </button>
                        <button ref={closeButtonRef} type="button" onClick={handleCloseRequest} className="p-1.5 rounded-full hover:bg-gray-700 transition btn-pressable"><Icons.XIcon className="h-5 w-5 text-white" /></button>
                    </div>
                </div>
                <div className="flex-grow p-4 relative min-h-0 overflow-auto" onClick={handleBackgroundClick}>
                    <svg id="tutorial-chart-svg" ref={svgRef} width="100%" height="100%" viewBox="0 0 800 600" onMouseMove={handleMouseMove} onMouseUp={handleMouseUp} onMouseLeave={handleMouseUp} className={mode === 'add_relation' ? 'cursor-crosshair' : ''} style={{ minWidth: '800px', minHeight: '600px' }}>
                        <defs>
                            {relationsWithCurveData.map(rel => {
                                const effectiveColor = rel.color || "#6b7280";
                                return (
                                    <marker key={rel.id} id={`arrow-${rel.id}`} viewBox="0 0 10 10" refX="9" refY="5" markerWidth="6" markerHeight="6" orient="auto-start-reverse">
                                        <path d="M 0 0 L 10 5 L 0 10 z" fill={effectiveColor} />
                                    </marker>
                                );
                            })}
                        </defs>

                        <g>
                            {relationsWithCurveData.map(rel => {
                                const source = nodesById[rel.source];
                                const target = nodesById[rel.target];
                                if (!source || !target) return null;

                                const effectiveColor = rel.color || "#6b7280";
                                const labelText = rel.callName ? `${rel.label} (${rel.callName})` : rel.label;
                                const labelWidth = labelText.length * 8 + 10;
                                const nodeRadius = 32;

                                const handleRelationClick = (e: React.MouseEvent) => {
                                    e.stopPropagation();
                                    if (mode === 'delete_relation') handleDeleteRelation(rel.id);
                                    else if (mode === 'navigate') setIsEditingRelation(rel);
                                };

                                if (source.id === target.id) {
                                    const loopGap = 2;
                                    const p1x = source.x - 2;
                                    const p1y = source.y - nodeRadius - loopGap;
                                    const p2x = source.x + 2;
                                    const p2y = source.y - nodeRadius - loopGap;
                                    const c1x = source.x - 40;
                                    const c1y = source.y - nodeRadius - 40;
                                    const c2x = source.x + 40;
                                    const c2y = source.y - nodeRadius - 40;

                                    const pathData = `M ${p1x} ${p1y} C ${c1x} ${c1y}, ${c2x} ${c2y}, ${p2x} ${p2y}`;
                                    const labelPos = { x: source.x, y: source.y - nodeRadius - 30 };

                                    return (
                                        <g key={rel.id} className="cursor-pointer">
                                            <path d={pathData} stroke="transparent" strokeWidth="15" fill="none" pointerEvents="stroke" onClick={handleRelationClick} />
                                            <path d={pathData} stroke={effectiveColor} strokeWidth="2" fill="none" markerEnd={`url(#arrow-${rel.id})`} pointerEvents="none" />
                                            <g onClick={handleRelationClick}>
                                                <rect x={labelPos.x - labelWidth / 2} y={labelPos.y - 10} width={labelWidth} height={20} fill="#1f2937" rx="4" />
                                                <text x={labelPos.x} y={labelPos.y} fill="#FFFFFF" textAnchor="middle" dy=".3em" fontSize="12">{labelText}</text>
                                            </g>
                                        </g>
                                    );
                                }

                                const dx = target.x - source.x;
                                const dy = target.y - source.y;
                                const dist = Math.sqrt(dx * dx + dy * dy);

                                const targetX = target.x - (dx / dist) * nodeRadius;
                                const targetY = target.y - (dy / dist) * nodeRadius;

                                let pathData, labelPos;
                                if (rel.curve !== 0) {
                                    const midX = (source.x + target.x) / 2;
                                    const midY = (source.y + target.y) / 2;
                                    const controlX = midX - (dy / dist) * rel.curve;
                                    const controlY = midY + (dx / dist) * rel.curve;
                                    pathData = `M ${source.x} ${source.y} Q ${controlX} ${controlY} ${targetX} ${targetY}`;
                                    labelPos = { x: controlX, y: controlY };
                                } else {
                                    pathData = `M ${source.x} ${source.y} L ${targetX} ${targetY}`;
                                    labelPos = { x: (source.x + target.x) / 2, y: (source.y + target.y) / 2 };
                                }

                                return (
                                    <g key={rel.id} className="cursor-pointer">
                                        <path d={pathData} stroke="transparent" strokeWidth="15" fill="none" pointerEvents="stroke" onClick={handleRelationClick} />
                                        <path d={pathData} stroke={effectiveColor} strokeWidth="2" fill="none" markerEnd={`url(#arrow-${rel.id})`} pointerEvents="none" />
                                        <g onClick={handleRelationClick}>
                                            <rect x={labelPos.x - labelWidth / 2} y={labelPos.y - 10} width={labelWidth} height={20} fill="#1f2937" rx="4" />
                                            <text x={labelPos.x} y={labelPos.y} fill="#FFFFFF" textAnchor="middle" dy=".3em" fontSize="12">{labelText}</text>
                                        </g>
                                    </g>
                                );
                            })}
                        </g>

                        <g>
                            {localNodes.map(node => (
                                <g key={node.id} transform={`translate(${node.x}, ${node.y})`} onMouseDown={(e) => handleMouseDown(e, node.id)} onClick={(e) => handleNodeClick(e, node)} className={`cursor-pointer ${mode === 'navigate' ? 'cursor-grab' : ''}`}>
                                    <circle r="30" fill="#2d3748" stroke={firstSelectionForAdd === node.id ? "#3b82f6" : (node.themeColor || "#4b5563")} strokeWidth="2"/>
                                    {node.appearance?.imageUrl ? (
                                        <image href={node.appearance.imageUrl} x="-25" y="-25" height="50" width="50" clipPath="circle(25px at center)" preserveAspectRatio="xMidYMin slice" />
                                    ) : (
                                        <text fill="#FFFFFF" textAnchor="middle" dy=".3em" fontSize="18">{node.name.substring(0, 1)}</text>
                                    )}
                                    <text y="45" fill="#FFFFFF" textAnchor="middle" fontSize="12">{node.name}</text>
                                </g>
                            ))}
                        </g>
                    </svg>
                    {mode === 'delete_relation' && (
                        <div className="absolute top-2 left-1/2 -translate-x-1/2 bg-red-500/50 text-white text-sm px-3 py-1 rounded-full pointer-events-none">
                            {firstSelectionForAdd ? '関係を削除する先のキャラクターを選択' : '関係の元となるキャラクターを選択、または削除したい関係の線をクリック'}
                        </div>
                    )}
                     {mode === 'add_relation' && (
                        <div className="absolute top-2 left-1/2 -translate-x-1/2 bg-blue-500/50 text-white text-sm px-3 py-1 rounded-full pointer-events-none">
                            {firstSelectionForAdd ? '関係を結ぶ先のキャラクターを選択' : '関係の元となるキャラクターを選択'}
                        </div>
                    )}
                </div>
                {isEditingRelation && (
                    <RelationEditor
                        relation={isEditingRelation}
                        characters={characters}
                        onSave={handleRelationSave}
                        onClose={() => setIsEditingRelation(null)}
                    />
                )}
                <div className="flex justify-between items-center p-4 border-t border-gray-700 flex-shrink-0">
                    <div>
                        {isMobile && <span className="text-xs text-orange-400 font-bold px-2 py-0.5 border border-orange-400 rounded">モバイル編集モード</span>}
                    </div>
                    <div className="flex gap-3">
                        <button type="button" onClick={handleCloseRequest} className="flex items-center gap-2 px-4 py-2 bg-gray-600 text-white rounded-md hover:bg-gray-500 transition btn-pressable">
                            <Icons.XIcon className="h-4 w-4" />
                            キャンセル
                        </button>
                        <button id="tutorial-chart-save-btn" type="button" onClick={handleSave} className="flex items-center gap-2 px-4 py-2 bg-indigo-600 text-white rounded-md hover:bg-indigo-500 transition btn-pressable">
                            <Icons.CheckIcon className="h-4 w-4" />
                            保存
                        </button>
                    </div>
                </div>
            </div>
        </div>,
        document.body
    );
};

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { createPortal } from 'react-dom';
import { v4 as uuidv4 } from 'uuid';
import * as Icons from '../icons';
import { getContrastingTextColor } from '../utils';
import { SettingItem, Relation, NodePosition } from '../types';
import { UnsavedChangesPopover } from './UnsavedChangesPopover';
import { useStore } from '../store/index';
import { ChartTutorial } from './ChartTutorial';

export const RelationEditor = ({ relation, characters, onSave, onClose }) => {
    const [label, setLabel] = useState(relation.label);
    const [color, setColor] = useState(relation.color);
    const [targetId, setTargetId] = useState(relation.target);
    const [callName, setCallName] = useState(relation.callName || '');

    const sourceChar = characters.find(c => c.id === relation.source);
    const targetChar = characters.find(c => c.id === targetId);

    const isMac = useMemo(() => navigator.platform.toUpperCase().indexOf('MAC') >= 0, []);
    const modifierKeyText = isMac ? '⌘Cmd' : 'Ctrl';

    const handleSave = () => {
        onSave({ ...relation, label, color, target: targetId, callName });
    };

    const handleKeyDown = (e: React.KeyboardEvent) => {
        if (e.key === 'Enter' && (e.ctrlKey || e.metaKey)) {
            e.preventDefault();
            handleSave();
        }
    };

    const presetColors = {
        '友好': '#14b8a6', // teal-500
        '敵対': '#f43f5e', // rose-500
        '協力': '#0ea5e9', // sky-500
        '恋愛': '#d946ef', // fuchsia-500
        '家族': '#f59e0b', // amber-500
        '師弟': '#8b5cf6', // violet-500
        '不明': '#6b7280'  // gray-500
    };

    const handlePresetClick = (presetLabel) => {
        setLabel(presetLabel);
        setColor(presetColors[presetLabel]);
    };

    return (
        <div className="absolute bottom-0 left-0 right-0 bg-gray-900/80 backdrop-blur-sm border-t border-gray-700 p-4 z-10" onKeyDown={handleKeyDown}>
            <div className="flex justify-between items-center mb-4">
                <h3 className="text-lg font-bold text-white">関係を編集</h3>
                <button type="button" onClick={onClose} className="p-1 rounded-full hover:bg-gray-700 btn-pressable"><Icons.XIcon className="h-5 w-5 text-white"/></button>
            </div>
            <div className="space-y-4">
                <p className="text-sm">
                    <span className="font-semibold text-blue-400">{sourceChar?.name || '不明'}</span><span className="text-white"> → </span><span className="font-semibold text-green-400">{targetChar?.name || '不明'}</span>
                </p>
                <div>
                    <label className="block text-xs text-white mb-1">関係の相手</label>
                    <select value={targetId} onChange={e => setTargetId(e.target.value)} className="w-full bg-gray-800 border border-gray-600 rounded-md px-3 py-1 text-sm text-white">
                        {characters.map(char => (
                            <option key={char.id} value={char.id}>{char.name}</option>
                        ))}
                    </select>
                </div>
                <div>
                    <label className="block text-xs text-white mb-1">関係性 (ラベル)</label>
                    <input type="text" value={label} onChange={e => setLabel(e.target.value)} className="w-full bg-gray-800 border border-gray-600 rounded-md px-3 py-1 text-sm text-white"/>
                </div>
                <div className="flex gap-2 flex-wrap">
                    {Object.entries(presetColors).map(([presetLabel, presetColor]) => (
                        <button key={presetLabel} type="button" onClick={() => handlePresetClick(presetLabel)} className="px-2 py-1 text-xs rounded-full btn-pressable" style={{ backgroundColor: presetColor, color: getContrastingTextColor(presetColor) }}>
                            {presetLabel}
                        </button>
                    ))}
                </div>
                 <div>
                    <label className="block text-xs text-white mb-1">呼び方 ({sourceChar?.name} → {targetChar?.name})</label>
                    <input type="text" value={callName} onChange={e => setCallName(e.target.value)} placeholder="例: 〇〇さん, 呼び捨て, あだ名" className="w-full bg-gray-800 border border-gray-600 rounded-md px-3 py-1 text-sm text-white"/>
                </div>
                <div>
                    <label className="block text-xs text-white mb-1">線の色</label>
                    <input
                        type="color"
                        value={color}
                        onChange={e => setColor(e.target.value)}
                        className="w-full h-10 p-1 bg-gray-900 border border-gray-600 rounded-md cursor-pointer"
                    />
                </div>
                 <div className="flex justify-end gap-3 pt-4 border-t border-gray-700/50">
                    <button type="button" onClick={handleSave} className="flex items-center gap-2 px-4 py-2 bg-indigo-600 text-white rounded-md hover:bg-indigo-500 transition font-semibold btn-pressable">
                        <Icons.CheckIcon className="h-4 w-4" />
                        保存 ({modifierKeyText}+Enter)
                    </button>
                </div>
            </div>
        </div>
    );
};

export const CharacterChartModal = ({ isOpen, onClose, characters, relations, nodePositions, onSave, onHelpClick, isMobile = false }) => {
    type LocalNode = SettingItem & NodePosition;
    const [localNodes, setLocalNodes] = useState<LocalNode[]>([]);
    const [localRelations, setLocalRelations] = useState(relations);
    const [activeDrag, setActiveDrag] = useState(null);
    const [isEditingRelation, setIsEditingRelation] = useState(null);
    const [mode, setMode] = useState<'navigate' | 'add_relation' | 'delete_relation'>('navigate');
    const [firstSelectionForAdd, setFirstSelectionForAdd] = useState<string | null>(null);
    const svgRef = useRef(null);
    const [isConfirmCloseOpen, setIsConfirmCloseOpen] = useState(false);
    const [initialStateString, setInitialStateString] = useState('');
    const closeButtonRef = useRef(null);
    // isOpenRefの初期値をfalseに固定し、確実に初回オープンを判定するように修正
    const isOpenRef = useRef(false);

    const hasCompletedGlobalChartTutorial = useStore(state => state.hasCompletedGlobalChartTutorial);
    const startChartTutorial = useStore(state => state.startChartTutorial);

    useEffect(() => {
        if (isOpen && !hasCompletedGlobalChartTutorial && !isMobile) {
            const timer = setTimeout(() => {
                startChartTutorial();
            }, 300);
            return () => clearTimeout(timer);
        }
    }, [isOpen, hasCompletedGlobalChartTutorial, startChartTutorial, isMobile]);

    // モーダルが開いた瞬間だけ初期データをセットするように修正（Propsの変更による自動リセットを防止）
    // 依存配列から relations 等を除外
    useEffect(() => {
        if (isOpen && !isOpenRef.current) {
            setLocalRelations(relations);
            setIsEditingRelation(null);
            setMode('navigate');
            setFirstSelectionForAdd(null);

            const chartWidth = 800;
            const chartHeight = 600;

            const updatedNodes = characters.map((char, index) => {
                const existingPos = nodePositions.find(p => p.characterId === char.id);
                if (existingPos) {
                    return { ...char, ...existingPos };
                }
                const angle = (index / characters.length) * 2 * Math.PI;
                const radius = Math.min(chartWidth, chartHeight) / 3;
                return {
                    ...char,
                    characterId: char.id,
                    x: chartWidth / 2 + radius * Math.cos(angle),
                    y: chartHeight / 2 + radius * Math.sin(angle),
                };
            });
            setLocalNodes(updatedNodes as LocalNode[]);
            const initialState = {
                relations,
                nodePositions: updatedNodes.map(n => ({ characterId: n.id, x: n.x, y: n.y }))
            };
            setInitialStateString(JSON.stringify(initialState));
        }
        isOpenRef.current = isOpen;
    }, [isOpen]); // 依存配列を最小限に

    useEffect(() => {
        setFirstSelectionForAdd(null);
    }, [mode]);

    const isDirty = useMemo(() => {
        if (!initialStateString) return false;
        const currentState = {
            relations: localRelations,
            nodePositions: localNodes.map(n => ({ characterId: n.id, x: n.x, y: n.y })),
        };
        return JSON.stringify(currentState) !== initialStateString;
    }, [localNodes, localRelations, initialStateString]);

    const relationsWithCurveData = useMemo(() => {
        const pairs = new Map<string, Relation[]>();
        localRelations.forEach(rel => {
            const key = [rel.source, rel.target].sort().join('--');
            if (!pairs.has(key)) {
                pairs.set(key, []);
            }
            pairs.get(key)!.push(rel);
        });

        return localRelations.map(rel => {
            const key = [rel.source, rel.target].sort().join('--');
            const pair = pairs.get(key)!;
            const isBidirectional = pair.length > 1 && pair.some(p => p.source === rel.target && p.target === rel.source);

            let curve = 0;
            if (isBidirectional) {
                curve = 30;
            }

            return { ...rel, curve };
        });
    }, [localRelations]);

    const handleSave = () => {
        const newPositions = localNodes.map(({ id, x, y }) => ({ characterId: id, x, y }));
        onSave(localRelations, newPositions);
        onClose();
    };

    const handleCloseRequest = () => {
        if (isDirty && !isMobile) {
            setIsConfirmCloseOpen(true);
        } else {
            onClose();
        }
    };

    const handleSaveAndClose = () => {
        handleSave();
        setIsConfirmCloseOpen(false);
    };

    const getSVGPoint = (e) => {
        const svg = svgRef.current;
        if (!svg) return { x: 0, y: 0 };
        const pt = svg.createSVGPoint();
        pt.x = e.clientX;
        pt.y = e.clientY;
        return pt.matrixTransform(svg.getScreenCTM().inverse());
    };

    const handleMouseDown = (e, nodeId) => {
        e.preventDefault();
        // モバイルガードを解除
        if (mode !== 'navigate') return;
        const point = getSVGPoint(e);
        const node = localNodes.find(n => n.id === nodeId);
        setActiveDrag({
            nodeId,
            offsetX: point.x - node.x,
            offsetY: point.y - node.y,
        });
    };

    const handleMouseMove = (e) => {
        if (!activeDrag) return;
        e.preventDefault();
        const point = getSVGPoint(e);
        setLocalNodes(prevNodes => prevNodes.map(node =>
            node.id === activeDrag.nodeId
                ? { ...node, x: point.x - activeDrag.offsetX, y: point.y - activeDrag.offsetY }
                : node
        ));
    };

    const handleMouseUp = (e) => {
        setActiveDrag(null);
    };

    const handleNodeClick = (e, node) => {
        e.stopPropagation(); 
        // モバイルガードを解除

        if (mode === 'add_relation') {
             if (!firstSelectionForAdd) {
                setFirstSelectionForAdd(node.id);
            } else {
                const existingRelation = localRelations.find(
                    r => r.source === firstSelectionForAdd && r.target === node.id
                );

                if (existingRelation) {
                    setIsEditingRelation(existingRelation);
                } else {
                    const newRelation: Relation = {
                        id: uuidv4(),
                        source: firstSelectionForAdd,
                        target: node.id,
                        label: "関係",
                        color: "#6b7280",
                        callName: ""
                    };
                    setIsEditingRelation(newRelation);
                }

                setMode('navigate');
                setFirstSelectionForAdd(null);
            }
        } else if (mode === 'delete_relation') {
            if (!firstSelectionForAdd) {
                setFirstSelectionForAdd(node.id);
            } else {
                const sourceId = firstSelectionForAdd;
                const targetId = node.id;

                if (sourceId !== targetId) {
                    const relationsToDelete = localRelations.filter(
                        r => (r.source === sourceId && r.target === targetId) ||
                             (r.source === targetId && r.target === sourceId)
                    );

                    if (relationsToDelete.length > 0) {
                        const sourceCharName = localNodes.find(n => n.id === sourceId)?.name || '不明なキャラクター';
                        const targetCharName = localNodes.find(n => n.id === targetId)?.name || '不明なキャラクター';
                        if (window.confirm(`${sourceCharName} と ${targetCharName} の間にあるすべての関係（${relationsToDelete.length}件）を削除しますか？`)) {
                            const idsToDelete = new Set(relationsToDelete.map(r => r.id));
                            setLocalRelations(prev => prev.filter(r => !idsToDelete.has(r.id)));
                        }
                    }
                }
                setFirstSelectionForAdd(null);
                // モードを維持し、連続削除を可能にする
            }
        }
    };

    const handleDeleteRelation = (relationId: string) => {
        setLocalRelations(prev => prev.filter(r => r.id !== relationId));
    };

    const handleRelationSave = (savedRelation) => {
        setLocalRelations(prev => {
            const exists = prev.some(r => r.id === savedRelation.id);
            if (exists) {
                return prev.map(r => r.id === savedRelation.id ? savedRelation : r);
            }
            return [...prev, savedRelation];
        });
        setIsEditingRelation(null);
    };

    const handleBackgroundClick = () => {
        if (mode === 'add_relation' && firstSelectionForAdd) {
            return;
        }
        setMode('navigate');
        setFirstSelectionForAdd(null);
    };

    if (!isOpen) return null;

    const nodesById = localNodes.reduce((acc, node) => ({ ...acc, [node.id]: node }), {});

    return createPortal(
        <div className="fixed inset-0 bg-black/80 backdrop-blur-sm flex justify-center items-center z-[70] p-4">
            {!isMobile && <ChartTutorial />}
            <div className="bg-gray-800 rounded-lg shadow-xl w-full max-w-5xl h-[90vh] flex flex-col border border-gray-700 relative">
                <UnsavedChangesPopover
                    isOpen={isConfirmCloseOpen}
                    targetRef={closeButtonRef}
                    onCancel={() => setIsConfirmCloseOpen(false)}
                    onCloseWithoutSaving={() => { setIsConfirmCloseOpen(false); onClose(); }}
                    onSaveAndClose={handleSaveAndClose}
                />
                <div className="flex justify-between items-center p-4 border-b border-gray-700 flex-shrink-0">
                    <div className="flex items-center gap-2">
                        <h2 className="text-xl font-bold text-violet-400 flex items-center"><Icons.UserCogIcon />キャラクター相関図</h2>
                    </div>
                     <div className="flex items-center gap-2">
                        <div className="flex items-center p-1 bg-gray-900 rounded-lg">
                            <button id="tutorial-chart-navigate-btn" onClick={() => setMode('navigate')} className={`px-3 py-1 text-xs rounded ${mode === 'navigate' ? 'bg-indigo-600' : ''} text-white btn-pressable`}>移動</button>
                            <button id="tutorial-chart-add-btn" onClick={() => setMode('add_relation')} className={`px-3 py-1 text-xs rounded ${mode === 'add_relation' ? 'bg-indigo-600' : ''} text-white btn-pressable`}>関係を追加</button>
                            <button id="tutorial-chart-delete-btn" onClick={() => setMode('delete_relation')} className={`px-3 py-1 text-xs rounded ${mode === 'delete_relation' ? 'bg-indigo-600' : ''} text-white btn-pressable`}>関係を削除</button>
                        </div>
                        <button onClick={() => onHelpClick('characterChart')} className="p-1.5 rounded-full text-gray-400 hover:text-white hover:bg-gray-700 transition btn-pressable" title="ヘルプ">
                            <Icons.HelpCircleIcon className="h-5 w-5" />
                        </button>
                        <button ref={closeButtonRef} type="button" onClick={handleCloseRequest} className="p-1.5 rounded-full hover:bg-gray-700 transition btn-pressable"><Icons.XIcon className="h-5 w-5 text-white" /></button>
                    </div>
                </div>
                <div className="flex-grow p-4 relative min-h-0 overflow-auto" onClick={handleBackgroundClick}>
                    <svg id="tutorial-chart-svg" ref={svgRef} width="100%" height="100%" viewBox="0 0 800 600" onMouseMove={handleMouseMove} onMouseUp={handleMouseUp} onMouseLeave={handleMouseUp} className={mode === 'add_relation' ? 'cursor-crosshair' : ''} style={{ minWidth: '800px', minHeight: '600px' }}>
                        <defs>
                            {relationsWithCurveData.map(rel => {
                                const effectiveColor = rel.color || "#6b7280";
                                return (
                                    <marker key={rel.id} id={`arrow-${rel.id}`} viewBox="0 0 10 10" refX="9" refY="5" markerWidth="6" markerHeight="6" orient="auto-start-reverse">
                                        <path d="M 0 0 L 10 5 L 0 10 z" fill={effectiveColor} />
                                    </marker>
                                );
                            })}
                        </defs>

                        <g>
                            {relationsWithCurveData.map(rel => {
                                const source = nodesById[rel.source];
                                const target = nodesById[rel.target];
                                if (!source || !target) return null;

                                const effectiveColor = rel.color || "#6b7280";
                                const labelText = rel.callName ? `${rel.label} (${rel.callName})` : rel.label;
                                const labelWidth = labelText.length * 8 + 10;
                                const nodeRadius = 32;

                                const handleRelationClick = (e: React.MouseEvent) => {
                                    e.stopPropagation();
                                    // モバイルガードを解除
                                    if (mode === 'delete_relation') handleDeleteRelation(rel.id);
                                    else if (mode === 'navigate') setIsEditingRelation(rel);
                                };

                                if (source.id === target.id) {
                                    const loopGap = 2;
                                    const p1x = source.x - 2;
                                    const p1y = source.y - nodeRadius - loopGap;
                                    const p2x = source.x + 2;
                                    const p2y = source.y - nodeRadius - loopGap;
                                    const c1x = source.x - 40;
                                    const c1y = source.y - nodeRadius - 40;
                                    const c2x = source.x + 40;
                                    const c2y = source.y - nodeRadius - 40;

                                    const pathData = `M ${p1x} ${p1y} C ${c1x} ${c1y}, ${c2x} ${c2y}, ${p2x} ${p2y}`;
                                    const labelPos = { x: source.x, y: source.y - nodeRadius - 30 };

                                    return (
                                        <g key={rel.id} className="cursor-pointer">
                                            <path d={pathData} stroke="transparent" strokeWidth="15" fill="none" pointerEvents="stroke" onClick={handleRelationClick} />
                                            <path d={pathData} stroke={effectiveColor} strokeWidth="2" fill="none" markerEnd={`url(#arrow-${rel.id})`} pointerEvents="none" />
                                            <g onClick={handleRelationClick}>
                                                <rect x={labelPos.x - labelWidth / 2} y={labelPos.y - 10} width={labelWidth} height={20} fill="#1f2937" rx="4" />
                                                <text x={labelPos.x} y={labelPos.y} fill="#FFFFFF" textAnchor="middle" dy=".3em" fontSize="12">{labelText}</text>
                                            </g>
                                        </g>
                                    );
                                }

                                const dx = target.x - source.x;
                                const dy = target.y - source.y;
                                const dist = Math.sqrt(dx * dx + dy * dy);

                                const targetX = target.x - (dx / dist) * nodeRadius;
                                const targetY = target.y - (dy / dist) * nodeRadius;

                                let pathData, labelPos;
                                if (rel.curve !== 0) {
                                    const midX = (source.x + target.x) / 2;
                                    const midY = (source.y + target.y) / 2;
                                    const controlX = midX - (dy / dist) * rel.curve;
                                    const controlY = midY + (dx / dist) * rel.curve;
                                    pathData = `M ${source.x} ${source.y} Q ${controlX} ${controlY} ${targetX} ${targetY}`;
                                    labelPos = { x: controlX, y: controlY };
                                } else {
                                    pathData = `M ${source.x} ${source.y} L ${targetX} ${targetY}`;
                                    labelPos = { x: (source.x + target.x) / 2, y: (source.y + target.y) / 2 };
                                }

                                return (
                                    <g key={rel.id} className="cursor-pointer">
                                        <path d={pathData} stroke="transparent" strokeWidth="15" fill="none" pointerEvents="stroke" onClick={handleRelationClick} />
                                        <path d={pathData} stroke={effectiveColor} strokeWidth="2" fill="none" markerEnd={`url(#arrow-${rel.id})`} pointerEvents="none" />
                                        <g onClick={handleRelationClick}>
                                            <rect x={labelPos.x - labelWidth / 2} y={labelPos.y - 10} width={labelWidth} height={20} fill="#1f2937" rx="4" />
                                            <text x={labelPos.x} y={labelPos.y} fill="#FFFFFF" textAnchor="middle" dy=".3em" fontSize="12">{labelText}</text>
                                        </g>
                                    </g>
                                );
                            })}
                        </g>

                        <g>
                            {localNodes.map(node => (
                                <g key={node.id} transform={`translate(${node.x}, ${node.y})`} onMouseDown={(e) => handleMouseDown(e, node.id)} onClick={(e) => handleNodeClick(e, node)} className={`cursor-pointer ${mode === 'navigate' ? 'cursor-grab' : ''}`}>
                                    <circle r="30" fill="#2d3748" stroke={firstSelectionForAdd === node.id ? "#3b82f6" : (node.themeColor || "#4b5563")} strokeWidth="2"/>
                                    {node.appearance?.imageUrl ? (
                                        <image href={node.appearance.imageUrl} x="-25" y="-25" height="50" width="50" clipPath="circle(25px at center)" preserveAspectRatio="xMidYMin slice" />
                                    ) : (
                                        <text fill="#FFFFFF" textAnchor="middle" dy=".3em" fontSize="18">{node.name.substring(0, 1)}</text>
                                    )}
                                    <text y="45" fill="#FFFFFF" textAnchor="middle" fontSize="12">{node.name}</text>
                                </g>
                            ))}
                        </g>
                    </svg>
                    {mode === 'delete_relation' && (
                        <div className="absolute top-2 left-1/2 -translate-x-1/2 bg-red-500/50 text-white text-sm px-3 py-1 rounded-full pointer-events-none">
                            {firstSelectionForAdd ? '関係を削除する先のキャラクターを選択' : '関係の元となるキャラクターを選択、または削除したい関係の線をクリック'}
                        </div>
                    )}
                     {mode === 'add_relation' && (
                        <div className="absolute top-2 left-1/2 -translate-x-1/2 bg-blue-500/50 text-white text-sm px-3 py-1 rounded-full pointer-events-none">
                            {firstSelectionForAdd ? '関係を結ぶ先のキャラクターを選択' : '関係の元となるキャラクターを選択'}
                        </div>
                    )}
                </div>
                {isEditingRelation && (
                    <RelationEditor
                        relation={isEditingRelation}
                        characters={characters}
                        onSave={handleRelationSave}
                        onClose={() => setIsEditingRelation(null)}
                    />
                )}
                <div className="flex justify-between items-center p-4 border-t border-gray-700 flex-shrink-0">
                    <div>
                        {isMobile && <span className="text-xs text-orange-400 font-bold px-2 py-0.5 border border-orange-400 rounded">モバイル編集モード</span>}
                    </div>
                    <div className="flex gap-3">
                        <button type="button" onClick={handleCloseRequest} className="flex items-center gap-2 px-4 py-2 bg-gray-600 text-white rounded-md hover:bg-gray-500 transition btn-pressable">
                            <Icons.XIcon className="h-4 w-4" />
                            キャンセル
                        </button>
                        <button id="tutorial-chart-save-btn" type="button" onClick={handleSave} className="flex items-center gap-2 px-4 py-2 bg-indigo-600 text-white rounded-md hover:bg-indigo-500 transition btn-pressable">
                            <Icons.CheckIcon className="h-4 w-4" />
                            保存
                        </button>
                    </div>
                </div>
            </div>
        </div>,
        document.body
    );
};

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { createPortal } from 'react-dom';
import { v4 as uuidv4 } from 'uuid';
import * as Icons from '../icons';
import { getContrastingTextColor } from '../utils';
import { SettingItem, Relation, NodePosition } from '../types';
import { UnsavedChangesPopover } from './UnsavedChangesPopover';
import { useStore } from '../store/index';
import { ChartTutorial } from './ChartTutorial';

export const RelationEditor = ({ relation, characters, onSave, onClose }) => {
    const [label, setLabel] = useState(relation.label);
    const [color, setColor] = useState(relation.color);
    const [targetId, setTargetId] = useState(relation.target);
    const [callName, setCallName] = useState(relation.callName || '');

    const sourceChar = characters.find(c => c.id === relation.source);
    const targetChar = characters.find(c => c.id === targetId);

    const isMac = useMemo(() => navigator.platform.toUpperCase().indexOf('MAC') >= 0, []);
    const modifierKeyText = isMac ? '⌘Cmd' : 'Ctrl';

    const handleSave = () => {
        onSave({ ...relation, label, color, target: targetId, callName });
    };

    const handleKeyDown = (e: React.KeyboardEvent) => {
        if (e.key === 'Enter' && (e.ctrlKey || e.metaKey)) {
            e.preventDefault();
            handleSave();
        }
    };

    const presetColors = {
        '友好': '#14b8a6', // teal-500
        '敵対': '#f43f5e', // rose-500
        '協力': '#0ea5e9', // sky-500
        '恋愛': '#d946ef', // fuchsia-500
        '家族': '#f59e0b', // amber-500
        '師弟': '#8b5cf6', // violet-500
        '不明': '#6b7280'  // gray-500
    };

    const handlePresetClick = (presetLabel) => {
        setLabel(presetLabel);
        setColor(presetColors[presetLabel]);
    };

    return (
        <div className="absolute bottom-0 left-0 right-0 bg-gray-900/80 backdrop-blur-sm border-t border-gray-700 p-4 z-10" onKeyDown={handleKeyDown}>
            <div className="flex justify-between items-center mb-4">
                <h3 className="text-lg font-bold text-white">関係を編集</h3>
                <button type="button" onClick={onClose} className="p-1 rounded-full hover:bg-gray-700 btn-pressable"><Icons.XIcon className="h-5 w-5 text-white"/></button>
            </div>
            <div className="space-y-4">
                <p className="text-sm">
                    <span className="font-semibold text-blue-400">{sourceChar?.name || '不明'}</span><span className="text-white"> → </span><span className="font-semibold text-green-400">{targetChar?.name || '不明'}</span>
                </p>
                <div>
                    <label className="block text-xs text-white mb-1">関係の相手</label>
                    <select value={targetId} onChange={e => setTargetId(e.target.value)} className="w-full bg-gray-800 border border-gray-600 rounded-md px-3 py-1 text-sm text-white">
                        {characters.map(char => (
                            <option key={char.id} value={char.id}>{char.name}</option>
                        ))}
                    </select>
                </div>
                <div>
                    <label className="block text-xs text-white mb-1">関係性 (ラベル)</label>
                    <input type="text" value={label} onChange={e => setLabel(e.target.value)} className="w-full bg-gray-800 border border-gray-600 rounded-md px-3 py-1 text-sm text-white"/>
                </div>
                <div className="flex gap-2 flex-wrap">
                    {Object.entries(presetColors).map(([presetLabel, presetColor]) => (
                        <button key={presetLabel} type="button" onClick={() => handlePresetClick(presetLabel)} className="px-2 py-1 text-xs rounded-full btn-pressable" style={{ backgroundColor: presetColor, color: getContrastingTextColor(presetColor) }}>
                            {presetLabel}
                        </button>
                    ))}
                </div>
                 <div>
                    <label className="block text-xs text-white mb-1">呼び方 ({sourceChar?.name} → {targetChar?.name})</label>
                    <input type="text" value={callName} onChange={e => setCallName(e.target.value)} placeholder="例: 〇〇さん, 呼び捨て, あだ名" className="w-full bg-gray-800 border border-gray-600 rounded-md px-3 py-1 text-sm text-white"/>
                </div>
                <div>
                    <label className="block text-xs text-white mb-1">線の色</label>
                    <input
                        type="color"
                        value={color}
                        onChange={e => setColor(e.target.value)}
                        className="w-full h-10 p-1 bg-gray-900 border border-gray-600 rounded-md cursor-pointer"
                    />
                </div>
                 <div className="flex justify-end gap-3 pt-4 border-t border-gray-700/50">
                    <button type="button" onClick={handleSave} className="flex items-center gap-2 px-4 py-2 bg-indigo-600 text-white rounded-md hover:bg-indigo-500 transition font-semibold btn-pressable">
                        <Icons.CheckIcon className="h-4 w-4" />
                        保存 ({modifierKeyText}+Enter)
                    </button>
                </div>
            </div>
        </div>
    );
};

export const CharacterChartModal = ({ isOpen, onClose, characters, relations, nodePositions, onSave, onHelpClick, isMobile = false }) => {
    type LocalNode = SettingItem & NodePosition;
    const [localNodes, setLocalNodes] = useState<LocalNode[]>([]);
    const [localRelations, setLocalRelations] = useState<Relation[]>([]);
    const [activeDrag, setActiveDrag] = useState(null);
    const [isEditingRelation, setIsEditingRelation] = useState(null);
    const [mode, setMode] = useState<'navigate' | 'add_relation' | 'delete_relation'>('navigate');
    const [firstSelectionForAdd, setFirstSelectionForAdd] = useState<string | null>(null);
    const svgRef = useRef(null);
    const [isConfirmCloseOpen, setIsConfirmCloseOpen] = useState(false);
    const [initialStateString, setInitialStateString] = useState('');
    const closeButtonRef = useRef(null);
    // マウント状態を追跡するRef
    const isOpenRef = useRef(false);

    const hasCompletedGlobalChartTutorial = useStore(state => state.hasCompletedGlobalChartTutorial);
    const startChartTutorial = useStore(state => state.startChartTutorial);

    useEffect(() => {
        if (isOpen && !hasCompletedGlobalChartTutorial && !isMobile) {
            const timer = setTimeout(() => {
                startChartTutorial();
            }, 300);
            return () => clearTimeout(timer);
        }
    }, [isOpen, hasCompletedGlobalChartTutorial, startChartTutorial, isMobile]);

    // モーダルが開いた瞬間「だけ」初期データをセットするように修正。
    // 依存配列に relations や nodePositions を含めないことで、編集中に外部からの上書きを防止する。
    useEffect(() => {
        if (isOpen && !isOpenRef.current) {
            setLocalRelations([...relations]); // 新しい参照としてコピー
            setIsEditingRelation(null);
            setMode('navigate');
            setFirstSelectionForAdd(null);

            const chartWidth = 800;
            const chartHeight = 600;

            const updatedNodes = characters.map((char, index) => {
                const existingPos = nodePositions.find(p => p.characterId === char.id);
                if (existingPos) {
                    return { ...char, ...existingPos };
                }
                const angle = (index / characters.length) * 2 * Math.PI;
                const radius = Math.min(chartWidth, chartHeight) / 3;
                return {
                    ...char,
                    characterId: char.id,
                    x: chartWidth / 2 + radius * Math.cos(angle),
                    y: chartHeight / 2 + radius * Math.sin(angle),
                };
            });
            setLocalNodes(updatedNodes as LocalNode[]);
            const initialState = {
                relations,
                nodePositions: updatedNodes.map(n => ({ characterId: n.id, x: n.x, y: n.y }))
            };
            setInitialStateString(JSON.stringify(initialState));
        }
        isOpenRef.current = isOpen;
    }, [isOpen]); // ここを [isOpen] のみに変更することで再初期化を防ぐ

    useEffect(() => {
        setFirstSelectionForAdd(null);
    }, [mode]);

    const isDirty = useMemo(() => {
        if (!initialStateString) return false;
        const currentState = {
            relations: localRelations,
            nodePositions: localNodes.map(n => ({ characterId: n.id, x: n.x, y: n.y })),
        };
        return JSON.stringify(currentState) !== initialStateString;
    }, [localNodes, localRelations, initialStateString]);

    const relationsWithCurveData = useMemo(() => {
        const pairs = new Map<string, Relation[]>();
        localRelations.forEach(rel => {
            const key = [rel.source, rel.target].sort().join('--');
            if (!pairs.has(key)) {
                pairs.set(key, []);
            }
            pairs.get(key)!.push(rel);
        });

        return localRelations.map(rel => {
            const key = [rel.source, rel.target].sort().join('--');
            const pair = pairs.get(key)!;
            const isBidirectional = pair.length > 1 && pair.some(p => p.source === rel.target && p.target === rel.source);

            let curve = 0;
            if (isBidirectional) {
                curve = 30;
            }

            return { ...rel, curve };
        });
    }, [localRelations]);

    const handleSave = () => {
        const newPositions = localNodes.map(({ id, x, y }) => ({ characterId: id, x, y }));
        onSave(localRelations, newPositions);
        onClose();
    };

    const handleCloseRequest = () => {
        if (isDirty && !isMobile) {
            setIsConfirmCloseOpen(true);
        } else {
            onClose();
        }
    };

    const handleSaveAndClose = () => {
        handleSave();
        setIsConfirmCloseOpen(false);
    };

    const getSVGPoint = (e) => {
        const svg = svgRef.current;
        if (!svg) return { x: 0, y: 0 };
        const pt = svg.createSVGPoint();
        pt.x = e.clientX;
        pt.y = e.clientY;
        return pt.matrixTransform(svg.getScreenCTM().inverse());
    };

    const handleMouseDown = (e, nodeId) => {
        e.preventDefault();
        if (mode !== 'navigate') return;
        const point = getSVGPoint(e);
        const node = localNodes.find(n => n.id === nodeId);
        setActiveDrag({
            nodeId,
            offsetX: point.x - node.x,
            offsetY: point.y - node.y,
        });
    };

    const handleMouseMove = (e) => {
        if (!activeDrag) return;
        e.preventDefault();
        const point = getSVGPoint(e);
        setLocalNodes(prevNodes => prevNodes.map(node =>
            node.id === activeDrag.nodeId
                ? { ...node, x: point.x - activeDrag.offsetX, y: point.y - activeDrag.offsetY }
                : node
        ));
    };

    const handleMouseUp = (e) => {
        setActiveDrag(null);
    };

    const handleNodeClick = (e, node) => {
        e.stopPropagation(); 

        if (mode === 'add_relation') {
             if (!firstSelectionForAdd) {
                setFirstSelectionForAdd(node.id);
            } else {
                const existingRelation = localRelations.find(
                    r => r.source === firstSelectionForAdd && r.target === node.id
                );

                if (existingRelation) {
                    setIsEditingRelation(existingRelation);
                } else {
                    const newRelation: Relation = {
                        id: uuidv4(),
                        source: firstSelectionForAdd,
                        target: node.id,
                        label: "関係",
                        color: "#6b7280",
                        callName: ""
                    };
                    setIsEditingRelation(newRelation);
                }

                setMode('navigate');
                setFirstSelectionForAdd(null);
            }
        } else if (mode === 'delete_relation') {
            if (!firstSelectionForAdd) {
                setFirstSelectionForAdd(node.id);
            } else {
                const sourceId = firstSelectionForAdd;
                const targetId = node.id;

                if (sourceId !== targetId) {
                    const relationsToDelete = localRelations.filter(
                        r => (r.source === sourceId && r.target === targetId) ||
                             (r.source === targetId && r.target === sourceId)
                    );

                    if (relationsToDelete.length > 0) {
                        const sourceCharName = localNodes.find(n => n.id === sourceId)?.name || '不明なキャラクター';
                        const targetCharName = localNodes.find(n => n.id === targetId)?.name || '不明なキャラクター';
                        if (window.confirm(`${sourceCharName} と ${targetCharName} の間にあるすべての関係（${relationsToDelete.length}件）を削除しますか？`)) {
                            // ペアベースで削除を実行
                            handleDeleteRelationByPair(sourceId, targetId);
                        }
                    }
                }
                setFirstSelectionForAdd(null);
            }
        }
    };

    // ペアベースの削除ロジック：始点と終点が一致するものを（ゴースト線含め）全て削除する
    const handleDeleteRelationByPair = (sourceId: string, targetId: string) => {
        setLocalRelations(prev => prev.filter(r => {
            const isMatch = (r.source === sourceId && r.target === targetId) ||
                           (r.source === targetId && r.target === sourceId);
            return !isMatch;
        }));
    };

    const handleRelationSave = (savedRelation) => {
        setLocalRelations(prev => {
            const exists = prev.some(r => r.id === savedRelation.id);
            if (exists) {
                return prev.map(r => r.id === savedRelation.id ? savedRelation : r);
            }
            return [...prev, savedRelation];
        });
        setIsEditingRelation(null);
    };

    const handleBackgroundClick = () => {
        if (mode === 'add_relation' && firstSelectionForAdd) {
            return;
        }
        setMode('navigate');
        setFirstSelectionForAdd(null);
    };

    if (!isOpen) return null;

    const nodesById = localNodes.reduce((acc, node) => ({ ...acc, [node.id]: node }), {});

    return createPortal(
        <div className="fixed inset-0 bg-black/80 backdrop-blur-sm flex justify-center items-center z-[70] p-4">
            {!isMobile && <ChartTutorial />}
            <div className="bg-gray-800 rounded-lg shadow-xl w-full max-w-5xl h-[90vh] flex flex-col border border-gray-700 relative">
                <UnsavedChangesPopover
                    isOpen={isConfirmCloseOpen}
                    targetRef={closeButtonRef}
                    onCancel={() => setIsConfirmCloseOpen(false)}
                    onCloseWithoutSaving={() => { setIsConfirmCloseOpen(false); onClose(); }}
                    onSaveAndClose={handleSaveAndClose}
                />
                <div className="flex justify-between items-center p-4 border-b border-gray-700 flex-shrink-0">
                    <div className="flex items-center gap-2">
                        <h2 className="text-xl font-bold text-violet-400 flex items-center"><Icons.UserCogIcon />キャラクター相関図</h2>
                    </div>
                     <div className="flex items-center gap-2">
                        <div className="flex items-center p-1 bg-gray-900 rounded-lg">
                            <button id="tutorial-chart-navigate-btn" onClick={() => setMode('navigate')} className={`px-3 py-1 text-xs rounded ${mode === 'navigate' ? 'bg-indigo-600' : ''} text-white btn-pressable`}>移動</button>
                            <button id="tutorial-chart-add-btn" onClick={() => setMode('add_relation')} className={`px-3 py-1 text-xs rounded ${mode === 'add_relation' ? 'bg-indigo-600' : ''} text-white btn-pressable`}>関係を追加</button>
                            <button id="tutorial-chart-delete-btn" onClick={() => setMode('delete_relation')} className={`px-3 py-1 text-xs rounded ${mode === 'delete_relation' ? 'bg-indigo-600' : ''} text-white btn-pressable`}>関係を削除</button>
                        </div>
                        <button onClick={() => onHelpClick('characterChart')} className="p-1.5 rounded-full text-gray-400 hover:text-white hover:bg-gray-700 transition btn-pressable" title="ヘルプ">
                            <Icons.HelpCircleIcon className="h-5 w-5" />
                        </button>
                        <button ref={closeButtonRef} type="button" onClick={handleCloseRequest} className="p-1.5 rounded-full hover:bg-gray-700 transition btn-pressable"><Icons.XIcon className="h-5 w-5 text-white" /></button>
                    </div>
                </div>
                <div className="flex-grow p-4 relative min-h-0 overflow-auto" onClick={handleBackgroundClick}>
                    <svg id="tutorial-chart-svg" ref={svgRef} width="100%" height="100%" viewBox="0 0 800 600" onMouseMove={handleMouseMove} onMouseUp={handleMouseUp} onMouseLeave={handleMouseUp} className={mode === 'add_relation' ? 'cursor-crosshair' : ''} style={{ minWidth: '800px', minHeight: '600px' }}>
                        <defs>
                            {relationsWithCurveData.map(rel => {
                                const effectiveColor = rel.color || "#6b7280";
                                return (
                                    <marker key={rel.id} id={`arrow-${rel.id}`} viewBox="0 0 10 10" refX="9" refY="5" markerWidth="6" markerHeight="6" orient="auto-start-reverse">
                                        <path d="M 0 0 L 10 5 L 0 10 z" fill={effectiveColor} />
                                    </marker>
                                );
                            })}
                        </defs>

                        <g>
                            {relationsWithCurveData.map(rel => {
                                const source = nodesById[rel.source];
                                const target = nodesById[rel.target];
                                if (!source || !target) return null;

                                const effectiveColor = rel.color || "#6b7280";
                                const labelText = rel.callName ? `${rel.label} (${rel.callName})` : rel.label;
                                const labelWidth = labelText.length * 8 + 10;
                                const nodeRadius = 32;

                                const handleRelationClick = (e: React.MouseEvent) => {
                                    e.stopPropagation();
                                    if (mode === 'delete_relation') {
                                        // 線をクリックした場合もペアベースで一括削除
                                        handleDeleteRelationByPair(rel.source, rel.target);
                                    } else if (mode === 'navigate') {
                                        setIsEditingRelation(rel);
                                    }
                                };

                                if (source.id === target.id) {
                                    const loopGap = 2;
                                    const p1x = source.x - 2;
                                    const p1y = source.y - nodeRadius - loopGap;
                                    const p2x = source.x + 2;
                                    const p2y = source.y - nodeRadius - loopGap;
                                    const c1x = source.x - 40;
                                    const c1y = source.y - nodeRadius - 40;
                                    const c2x = source.x + 40;
                                    const c2y = source.y - nodeRadius - 40;

                                    const pathData = `M ${p1x} ${p1y} C ${c1x} ${c1y}, ${c2x} ${c2y}, ${p2x} ${p2y}`;
                                    const labelPos = { x: source.x, y: source.y - nodeRadius - 30 };

                                    return (
                                        <g key={rel.id} className="cursor-pointer">
                                            <path d={pathData} stroke="transparent" strokeWidth="15" fill="none" pointerEvents="stroke" onClick={handleRelationClick} />
                                            <path d={pathData} stroke={effectiveColor} strokeWidth="2" fill="none" markerEnd={`url(#arrow-${rel.id})`} pointerEvents="none" />
                                            <g onClick={handleRelationClick}>
                                                <rect x={labelPos.x - labelWidth / 2} y={labelPos.y - 10} width={labelWidth} height={20} fill="#1f2937" rx="4" />
                                                <text x={labelPos.x} y={labelPos.y} fill="#FFFFFF" textAnchor="middle" dy=".3em" fontSize="12">{labelText}</text>
                                            </g>
                                        </g>
                                    );
                                }

                                const dx = target.x - source.x;
                                const dy = target.y - source.y;
                                const dist = Math.sqrt(dx * dx + dy * dy);

                                const targetX = target.x - (dx / dist) * nodeRadius;
                                const targetY = target.y - (dy / dist) * nodeRadius;

                                let pathData, labelPos;
                                if (rel.curve !== 0) {
                                    const midX = (source.x + target.x) / 2;
                                    const midY = (source.y + target.y) / 2;
                                    const controlX = midX - (dy / dist) * rel.curve;
                                    const controlY = midY + (dx / dist) * rel.curve;
                                    pathData = `M ${source.x} ${source.y} Q ${controlX} ${controlY} ${targetX} ${targetY}`;
                                    labelPos = { x: controlX, y: controlY };
                                } else {
                                    pathData = `M ${source.x} ${source.y} L ${targetX} ${targetY}`;
                                    labelPos = { x: (source.x + target.x) / 2, y: (source.y + target.y) / 2 };
                                }

                                return (
                                    <g key={rel.id} className="cursor-pointer">
                                        <path d={pathData} stroke="transparent" strokeWidth="15" fill="none" pointerEvents="stroke" onClick={handleRelationClick} />
                                        <path d={pathData} stroke={effectiveColor} strokeWidth="2" fill="none" markerEnd={`url(#arrow-${rel.id})`} pointerEvents="none" />
                                        <g onClick={handleRelationClick}>
                                            <rect x={labelPos.x - labelWidth / 2} y={labelPos.y - 10} width={labelWidth} height={20} fill="#1f2937" rx="4" />
                                            <text x={labelPos.x} y={labelPos.y} fill="#FFFFFF" textAnchor="middle" dy=".3em" fontSize="12">{labelText}</text>
                                        </g>
                                    </g>
                                );
                            })}
                        </g>

                        <g>
                            {localNodes.map(node => (
                                <g key={node.id} transform={`translate(${node.x}, ${node.y})`} onMouseDown={(e) => handleMouseDown(e, node.id)} onClick={(e) => handleNodeClick(e, node)} className={`cursor-pointer ${mode === 'navigate' ? 'cursor-grab' : ''}`}>
                                    <circle r="30" fill="#2d3748" stroke={firstSelectionForAdd === node.id ? "#3b82f6" : (node.themeColor || "#4b5563")} strokeWidth="2"/>
                                    {node.appearance?.imageUrl ? (
                                        <image href={node.appearance.imageUrl} x="-25" y="-25" height="50" width="50" clipPath="circle(25px at center)" preserveAspectRatio="xMidYMin slice" />
                                    ) : (
                                        <text fill="#FFFFFF" textAnchor="middle" dy=".3em" fontSize="18">{node.name.substring(0, 1)}</text>
                                    )}
                                    <text y="45" fill="#FFFFFF" textAnchor="middle" fontSize="12">{node.name}</text>
                                </g>
                            ))}
                        </g>
                    </svg>
                    {mode === 'delete_relation' && (
                        <div className="absolute top-2 left-1/2 -translate-x-1/2 bg-red-500/50 text-white text-sm px-3 py-1 rounded-full pointer-events-none">
                            {firstSelectionForAdd ? '関係を削除する先のキャラクターを選択' : '関係の元となるキャラクターを選択、または削除したい関係の線をクリック'}
                        </div>
                    )}
                     {mode === 'add_relation' && (
                        <div className="absolute top-2 left-1/2 -translate-x-1/2 bg-blue-500/50 text-white text-sm px-3 py-1 rounded-full pointer-events-none">
                            {firstSelectionForAdd ? '関係を結ぶ先のキャラクターを選択' : '関係の元となるキャラクターを選択'}
                        </div>
                    )}
                </div>
                {isEditingRelation && (
                    <RelationEditor
                        relation={isEditingRelation}
                        characters={characters}
                        onSave={handleRelationSave}
                        onClose={() => setIsEditingRelation(null)}
                    />
                )}
                <div className="flex justify-between items-center p-4 border-t border-gray-700 flex-shrink-0">
                    <div>
                        {isMobile && <span className="text-xs text-orange-400 font-bold px-2 py-0.5 border border-orange-400 rounded">モバイル編集モード</span>}
                    </div>
                    <div className="flex gap-3">
                        <button type="button" onClick={handleCloseRequest} className="flex items-center gap-2 px-4 py-2 bg-gray-600 text-white rounded-md hover:bg-gray-500 transition btn-pressable">
                            <Icons.XIcon className="h-4 w-4" />
                            キャンセル
                        </button>
                        <button id="tutorial-chart-save-btn" type="button" onClick={handleSave} className="flex items-center gap-2 px-4 py-2 bg-indigo-600 text-white rounded-md hover:bg-indigo-500 transition btn-pressable">
                            <Icons.CheckIcon className="h-4 w-4" />
                            保存
                        </button>
                    </div>
                </div>
            </div>
        </div>,
        document.body
    );
};

